import { Guid } from 'guid-typescript';
import { Observable, Subject } from 'rxjs';
import { finalize } from 'rxjs/operators';
import { Md5 } from 'ts-md5';
import { ProgramType } from '../types/context/program.context';
import { getProgramTypeFromContext } from './validation-context-holder';

export const UNSUBSCRIBE_MESSAGE_TYPE = 'ur.web.message.unsubscribeUpdates';

/**
 * Options for creating a UREventTarget
 * @param name For manually setting the name of the event target. Will take precedence if provided.
 * @param values String values that will be hashed to create the event target name.
 * @param salt Salt to add to the event target name. Will be appended.
 */
type UREventTargetOptions = {
    name?: string;
    values?: Array<string>;
    salt?: string;
};
/**
 *
 */
export class UREventTarget extends EventTarget {
    name?: string;
    /**
     *
     * @param name
     */
    constructor(options?: UREventTargetOptions) {
        super();
        this.name = options?.name || Md5.hashStr(`${options?.values?.join('')}${options?.salt}`);
    }
}

/**
 * An interface representing the ability to post messages
 */
export interface WorkerScopeInterface extends EventTarget {
    name?: string;
    postMessage(message: unknown, transfer?: Transferable[]): void;
}

/**
 * returns true if the item is a worker type
 * @param item
 */
export function isWorkerScope(item: EventTarget): item is WorkerScopeInterface {
    return (item as any).postMessage && typeof (item as any).postMessage === 'function';
}

/**
 * Interface for deferred invocation of a promise response
 */
interface PromiseResponder {
    resolve: (value: any) => void;
    reject: (reason?: any) => void;
}

/**
 *
 */
export abstract class Serializer {
    abstract serialize(serializerType: string, obj: any): { serializerType: string; serializedObject: any; transferables: Transferable[] };
}

/**
 * Abstract interface for communication within PSX
 *
 * This class is an internal implementation detail used by higher-level contribution APIs.
 */
export abstract class CommunicationChannel {
    abstract request<T>(type: string, data: any, serializers?: Map<string, Serializer>, programType?: ProgramType): Promise<T>;

    /**
     * returns an observable that will emit any messages replied to the specified message
     *
     * @param type The type of message being sent
     * @param data The message data
     */
    abstract requestObserve<T>(type: string, data: any, programType?: ProgramType): Observable<T>;

    private readonly requestResponders = new Map<string, PromiseResponder>();
    private readonly observerResponders = new Map<string, any>();
    private readonly workerTriggers = new Map<string, any>();

    /**
     *
     */
    addWorkerTrigger(type: string, callback: (event: any) => void) {
        this.workerTriggers.set(type, callback);
    }

    /**
     *
     */
    private triggerRequestResponse(event: MessageEvent, responder: PromiseResponder) {
        if (event.data.error) {
            responder.reject(event.data.error);
        } else {
            responder.resolve(event.data.data);
        }
    }

    /**
     *
     */
    private triggerObserverResponse(event: MessageEvent, responder: any) {
        if (event.data.error) {
            responder.error(event.data.error);
        } else {
            responder.next(event.data.data);
        }
    }

    /**
     *
     */
    protected handleMessage(event: MessageEvent) {
        const responder = this.requestResponders.get(event.data.id);
        if (responder) {
            this.triggerRequestResponse(event, responder);
            this.requestResponders.delete(event.data.id);
            return;
        }

        const observerResponder = this.observerResponders.get(event.data.id);
        if (observerResponder) {
            this.triggerObserverResponse(event, observerResponder);
        }

        const workerTrigger = this.workerTriggers.get(event.data.type);
        if (workerTrigger) {
            workerTrigger(event.data);
        }
    }

    /**
     *
     */
    convertSerializableObjects(data: any, serializers?: Map<string, Serializer>): { data: any; transferables: Transferable[] } {
        if (!data.serializableObjects || !serializers) {
            return { data, transferables: [] as Transferable[] };
        }
        const { transferables: serializedTransferables, serializedObjects } = data.serializableObjects.reduce(
            (acc: { transferables: Set<Transferable>; serializedObjects: any[] }, obj: any) => {
                const serializer = serializers.get(obj.serializerType);
                if (serializer) {
                    const result = serializer.serialize(obj.serializerType, obj.object);
                    acc.transferables = new Set<Transferable>([...acc.transferables, ...result.transferables]);
                    acc.serializedObjects.push({
                        serializerType: result.serializerType,
                        serializedObject: result.serializedObject,
                    });
                    return acc;
                }
                return acc;
            },
            { transferables: new Set<Transferable>(), serializedObjects: [] },
        );

        data.serializedObjects = serializedObjects;
        delete data.serializableObjects;
        return { data, transferables: Array.from(serializedTransferables) };
    }

    /**
     *
     */
    requestInternal<T>(
        sender: any,
        type: string,
        name: string | undefined,
        data: any = {},
        transferables: Transferable[] = [],
        programType?: ProgramType,
    ): Promise<T> {
        const id = Guid.raw();
        const promise = new Promise<T>((resolve, reject) => {
            this.requestResponders.set(id, { resolve, reject });
        });

        const message: { type: string; data: unknown; id: string; name?: string; serializedObjects?: []; programType?: ProgramType } = {
            type,
            data,
            id,
        };
        if (name) {
            message.name = name;
        }
        if (programType !== undefined) {
            message.programType = programType;
        }
        sender(message, transferables);
        return promise;
    }

    /**
     *
     */
    protected requestObserveInternal<T>(sender: any, type: string, data: any, programType?: ProgramType): Observable<T> {
        const id = Guid.raw();
        const response$ = new Subject<T>();

        this.observerResponders.set(id, response$);

        const message: { type: string; data: any; id: string; programType?: ProgramType } = {
            type,
            data: {
                ...data,
            },
            id,
        };
        if (programType !== undefined) {
            message.programType = programType;
        }
        sender(message);
        return response$.pipe(finalize(() => this.unsubscribeFinalized(id, sender)));
    }

    /**
     *
     */
    protected unsubscribeFinalized(id: string, sender: any) {
        this.observerResponders.delete(id);
        const unsubscribeMessage = {
            type: UNSUBSCRIBE_MESSAGE_TYPE,
            data: { id },
        };
        sender(unsubscribeMessage);
    }
}

/**
 * Communication implementation for workers in PSX
 *
 * This class is an internal implementation detail used by higher-level contribution APIs.
 */
export class WorkerCommunicationChannel extends CommunicationChannel {
    portToMainThread: MessagePort;
    messageChannel: MessageChannel;

    id = Guid.raw();

    /**
     *
     */
    constructor(readonly worker: WorkerScopeInterface) {
        super();
        this.messageChannel = new MessageChannel();
        this.portToMainThread = this.messageChannel.port1;

        this.portToMainThread.addEventListener('message', (event) => {
            this.handleMessage(event);
        });

        this.portToMainThread.start();

        worker.postMessage({ type: 'handshake' }, [this.messageChannel.port2]);
    }

    /**
     *
     */
    request<T>(type: string, data: any = {}, serializers?: Map<string, Serializer>, programType?: ProgramType): Promise<T> {
        const { data: convertedData, transferables } = this.convertSerializableObjects(data, serializers);

        return this.requestInternal<T>(
            (message: any, transferables: Transferable[]) => {
                this.dispatchWorkerEvent(message, transferables);
            },
            type,
            this.worker.name,
            convertedData,
            transferables,
            programType,
        );
    }

    /**
     *
     */
    private dispatchWorkerEvent(message: unknown, transferables: Transferable[]) {
        this.portToMainThread.postMessage(message, transferables);
    }

    /**
     * returns an observable that will emit any messages replied to the specified message
     *
     * @param type The type of message being sent
     * @param data The message data
     */
    requestObserve<T>(type: string, data: any = {}, programType?: ProgramType): Observable<T> {
        return this.requestObserveInternal<T>(
            (message: any) => {
                this.dispatchWorkerEvent(message, []);
            },
            type,
            data,
            programType,
        );
    }
}

/**
 * Communication implementation for presenters in PSX
 *
 * This class is an internal implementation detail used by higher-level contribution APIs.
 */
export class EventTargetCommunicationChannel extends CommunicationChannel {
    private readonly eventTarget: EventTarget;
    private responseListenerAttached = false;

    /**
     *
     */
    constructor(eventTarget: EventTarget) {
        super();
        this.eventTarget = eventTarget;
        if (isWorkerScope(this.eventTarget)) {
            throw new Error('Use WorkerCommunicationChannel for communication with workers');
        }
    }

    /**
     *
     */
    private ensureResponseListener() {
        if (this.responseListenerAttached) {
            return;
        }
        this.responseListenerAttached = true;
        this.eventTarget.addEventListener('response', (event) => {
            this.handleMessage(event as MessageEvent);
        });
    }

    /**
     *
     */
    request<T>(type: string, data: any = {}, serializers?: Map<string, Serializer>, programType?: ProgramType): Promise<T> {
        const { data: convertedData } = this.convertSerializableObjects(data, serializers);
        this.ensureResponseListener();
        return this.requestInternal<T>(
            (message: any) => {
                this.dispatchTargetEvent(message);
            },
            type,
            (this.eventTarget as UREventTarget)?.name,
            convertedData,
            [],
            programType,
        );
    }

    /**
     *
     */
    private dispatchTargetEvent(message: unknown) {
        this.eventTarget.dispatchEvent(new MessageEvent('request', { data: message }));
    }

    /**
     * returns an observable that will emit any messages replied to the specified message
     *
     * @param type The type of message being sent
     * @param data The message data
     */
    requestObserve<T>(type: string, data: any = {}, programType?: ProgramType): Observable<T> {
        this.ensureResponseListener();
        return this.requestObserveInternal<T>(
            (message: any) => {
                this.dispatchTargetEvent(message);
            },
            type,
            data,
            programType,
        );
    }
}

/**
 * And event target or communication channel
 */
export type EventTargetOrCommChannel = UREventTarget | CommunicationChannel;

/**
 * returns true if the item is a CommunicationChannel type
 * @param item
 */
export function isCommunicationChannel(item: EventTargetOrCommChannel): item is CommunicationChannel {
    return (item as any).request && typeof (item as any).request === 'function';
}

/**
 * Creates a WorkerCommunicationChannel
 * @param target
 */
export function createWorkerCommChannel(target: EventTargetOrCommChannel) {
    let communicationChannel: CommunicationChannel;
    if (isCommunicationChannel(target)) {
        communicationChannel = target;
    } else {
        communicationChannel = new WorkerCommunicationChannel(target as WorkerScopeInterface);
    }
    return communicationChannel;
}

/**
 * Creates a EventTargetCommunicationChannel
 * @param target
 */
export function createEventTargetCommChannel(target: EventTargetOrCommChannel) {
    let communicationChannel: CommunicationChannel;
    if (isCommunicationChannel(target)) {
        communicationChannel = target;
    } else {
        communicationChannel = new EventTargetCommunicationChannel(target as WorkerScopeInterface);
    }
    return communicationChannel;
}

/**
 * Base class for invoking messages
 */
export abstract class MessageInvokerService {
    communicationChannel: CommunicationChannel;
    /**
     * @constructor
     * @param messageBase
     * @param eventTarget
     */
    protected constructor(
        private readonly messageBase: string,
        readonly eventTarget: EventTargetOrCommChannel,
    ) {
        if (isCommunicationChannel(eventTarget)) {
            this.communicationChannel = eventTarget;
        } else {
            if (isWorkerScope(eventTarget)) {
                this.communicationChannel = new WorkerCommunicationChannel(eventTarget);
            } else {
                this.communicationChannel = new EventTargetCommunicationChannel(eventTarget);
            }
        }
    }

    /**
     * returns a reply promise for the requested message
     *
     * @param type The type of message being sent
     * @param data The message data
     */
    request<T>(type: string, data: any = {}, serializers?: Map<string, Serializer>): Promise<T> {
        return this.communicationChannel.request(this.messageBase + type, data, serializers);
    }

    /**
     * returns an observable that will emit any messages replied to the requested message
     *
     * @param type The type of message being sent
     * @param data The message data
     */
    requestObserve<T>(type: string, data: any = {}): Observable<T> {
        return this.communicationChannel.requestObserve(this.messageBase + type, data);
    }

    /**
     * returns a reply promise to the specified message
     *
     * @param type The type of message being sent
     * @param data The message data
     */
    postAndAwait<T>(type: string, data: any = {}): Promise<T> {
        const { programType, cleanData } = this.extractProgramType(data);
        return this.communicationChannel.request(this.messageBase + type, cleanData, undefined, programType);
    }

    /**
     * returns an observable that will emit any messages replied to the specified message
     *
     * @param type The type of message being sent
     * @param data The message data
     */
    postAndObserve<T>(type: string, data: any = {}): Observable<T> {
        const { programType, cleanData } = this.extractProgramType(data);
        return this.communicationChannel.requestObserve(this.messageBase + type, cleanData, programType);
    }

    /**
     * @internal Extracts programType from either the data payload or the validation context,
     * and returns it separately so it can be placed on the base message rather than the payload.
     */
    private extractProgramType(data: any): { programType: ProgramType | undefined; cleanData: any } {
        if (typeof data !== 'object' || data === null) {
            return { programType: getProgramTypeFromContext(), cleanData: data };
        }

        const explicitProgramType = data.programType;
        const contextProgramType = getProgramTypeFromContext();
        const programType = explicitProgramType ?? contextProgramType;

        if ('programType' in data) {
            const { programType: _, ...cleanData } = data;
            return { programType, cleanData };
        }

        return { programType, cleanData: data };
    }
}
