import { TabInputInsertableModel } from '@universal-robots/ui-models';
import { ExpressionEditorData, ExpressionEditorValue } from '../../types/common/expression-editor';
import { EventTargetOrCommChannel, MessageInvokerService } from '../message-invoker';

export const EXPRESSION_EDITOR_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.ExpressionEditorService.';

/**
 * Service that handles editing expressions
 */
export class ExpressionEditorService extends MessageInvokerService {
    /**
     * Create a service for the specific eventTarget
     * @param eventTarget
     */
    constructor(override readonly eventTarget: EventTargetOrCommChannel) {
        super(EXPRESSION_EDITOR_SERVICE_MESSAGE_TYPE_BASE, eventTarget);
    }

    /**
     * Returns content that can be inserted on the expression tab of the tab input
     * @returns Arrays of the different types of insertables, eg inputs, outputs, built in
     * functions
     */
    getTabInputInsertableModel(): Promise<TabInputInsertableModel> {
        return this.postAndAwait('getTabInputInsertableModel');
    }

    /**
     * Opens the expression editor dialog
     * @param data The data to initialize the expression editor with
     * @returns The result of the expression editor dialog
     */
    openExpressionEditor(data: ExpressionEditorData): Promise<ExpressionEditorValue | undefined> {
        return this.postAndAwait('openExpressionEditor', data);
    }

    /**
     * Returns script given a ExpressionEditorValue
     * @param value The ExpressionEditorValue to get the script for
     * @returns The script for the ExpressionEditorValue
     */
    getScript(value: ExpressionEditorValue): Promise<string> {
        return this.postAndAwait('getScript', value);
    }
}
