import { converter, FixedPointNumber, Unit, UnitType, isUnit } from '@universal-robots/utilities-units';
import { AllUnits, Value } from './value';
import { ValueObjectMap } from './value-object-map';

/**
 * Converts one value object to another one with a different compatible unit
 * @example
 * ```ts
 *  const value = { value: 1, unit: m/s };
 *  const toUnit = mm/s;
 *  const convertedValue = convertValue(value, toUnit);
 *  console.log(convertedValue); // outputs { value: 1000, unit: mm/s };
 * ```
 * @throws Error if the value object and the provided unit are incompatible
 * @param value The value object to be converted
 * @param toUnit The unit to convert into, must be compatible with the value object's unit
 * @returns a new value object that contains the converted value
 * @see valueRawConverter
 */
/**
 * Converts a value to the given unit. Use this when you have a Unit object (e.g. from utilities-units)
 * and need the converted Value.
 * @param value The value object to be converted
 * @param unit The unit to convert into
 * @returns The converted value object
 */
export function convertValueToUnit<T extends UnitType>(value: Value, unit: Unit<T>): Value {
    return convertValue(value, unit.label);
}

export function convertValue<T extends Value>(value: T, toUnit: T['unit']): Value<T['unit']> {
    if (!Object.keys(ValueObjectMap).includes(value.unit)) {
        throw new Error(`Unknown unit in value ${value.unit}`);
    }
    if (!Object.keys(ValueObjectMap).includes(toUnit)) {
        throw new Error(`Unknown target unit ${toUnit}`);
    }
    const from: Unit = ValueObjectMap[value.unit];
    const to: Unit = ValueObjectMap[toUnit];
    if (from.quantity.quantity !== to.quantity.quantity) {
        throw new Error('Cannot convert mismatched units');
    }
    const originalValue = new FixedPointNumber(value.value, from);
    const newValue = converter(originalValue, to);
    return {
        value: newValue.getValue(),
        unit: toUnit,
    };
}
/**
 * @example
 * ```ts
 * const unitLabel = "mm";
 * const unit = getUnitFromLabel<LengthUnit>(unitLabel);
 * console.log(unit); // outputs Unit object for millimeter
 * ```
 *
 * @param unitLabel
 * @returns
 */
export function getUnitFromLabel<T extends UnitType>(unitLabel: AllUnits): Unit<T> {
    if (!Object.keys(ValueObjectMap).includes(unitLabel)) {
        throw new Error(`Unknown target unit ${unitLabel}`);
    }
    return ValueObjectMap[unitLabel] as Unit<T>;
}

/**
 * Get the fixed numeric value of a value object converted into another compatible unit with the correct number of significant digits
 * @example
 * ```ts
 *  const value = { value: 1.1254323, unit: "m" };
 *  const fixedValue = valueFixedConverter(value, 'mm');
 *  console.log(fixedValue); // outputs 1125.432
 * ```
 * @throws Error if the value object and the provided unit are incompatible
 * @param value The value object to be converted
 * @param to The unit to convert into, must be compatible with the value object's unit
 * @returns The fixed numeric value of the converted value object
 */

export function valueFixedConverter<T extends UnitType>(value: Value, to: Unit<T> | AllUnits): number {
    const targetUnit: Unit<T> = isUnit(to) ? to : getUnitFromLabel<T>(to);
    const convertedValue = convertValue(value, targetUnit.label);
    return new FixedPointNumber(Number(convertedValue.value), targetUnit).getFixedValue();
}

/**
 * Get the raw numeric value of a value object converted into another compatible unit as a string
 * <p>The returned value is formatted using {@link FixedPointNumber#getDisplayValue} and is without any unit symbols or label</p>
 * @example
 * ```ts
 *  const value = { value: 1, unit: "m/s" };
 *  const toUnit = "mm/s";
 *  const convertedValue = valueRawConverter(value, toUnit);
 *  console.log(convertedValue); // outputs "1000"
 * ```
 * @throws Error if the value object and the provided unit are incompatible
 * @param value The value object to be converted
 * @param to The unit to convert into, must be compatible with the value object's unit
 * @returns The raw numeric value of the converted value object as a formatted string
 * @see convertValue
 */
export function valueRawConverter<T extends UnitType>(value: Value, to: Unit<T>): string {
    const convertedValue = convertValue(value, to.label);
    return `${new FixedPointNumber(Number(convertedValue.value), to).getDisplayValue()}`;
}

/**
 * Transform the value object into a formatted string converting it to the specified unit with the unit's symbol appended
 * <p>The returned value is formatted using {@link FixedPointNumber#getDisplayValue} and is without any unit symbols or label</p>
 * @example
 * ```ts
 *  const value = { value: 1, unit: "m/s" };
 *  const toUnit = "mm/s";
 *  const convertedValue = valueConverter(value, toUnit);
 *  console.log(convertedValue); // outputs "1000 mm/s"
 * ```
 * @throws Error if the value object and the provided unit are incompatible
 * @param value The value object to be formatted
 * @param to The unit to convert into, must be compatible with the value object's unit
 * @returns The formatted value with the unit's symbol appended
 */
export function valueConverter<T extends UnitType>(value: Value, to: Unit<T>): string {
    const convertedValue = convertValue(value, to.label);
    return `${new FixedPointNumber(Number(convertedValue.value), to).getDisplayValue()} ${to.symbol}`;
}
