import { SelectedType, TabInputValue } from '@universal-robots/ui-models';
import { ProgramNode, SignalValue } from '../..';
import { TabInputModel } from '../../../common';
import { SignalValueTypeEnum } from '../../../sources';
import { VARIABLE_VALUE_TYPES, VariableReference } from '../../../symbols';
import { Time } from '../../../values';
import { NodeType } from './program-node-type';

export const floatOperators = ['<', '>'] as const;
export const registerOperators = [...floatOperators, '==', '!=', '>=', '<='] as const;
export const operatorInverseMap = {
    '<': '>=',
    '>': '<=',
    '==': '!=',
    '!=': '==',
    '>=': '<',
    '<=': '>',
} as const;

export type floatOperator = (typeof floatOperators)[number];
export type registerOperator = (typeof registerOperators)[number];
export interface WaitNodeSignalInput {
    groupId?: string;
    sourceID?: string;
    signalID?: string;
    selectedType?: SelectedType;
    floatOperator?: floatOperator;
    registerOperator?: registerOperator;
    value?: SignalValue;
    signalValueType?: SignalValueTypeEnum;
}

export interface WaitNodeVariableReference {
    // Additional properties related to the assigned value:
    valueType: (typeof VARIABLE_VALUE_TYPES)[number]; // The last known type of the assignment value. Used for validation - that the assigned value (tapInput component just returns a string) matches the type of the node's referenced variable.
    valueReference?: VariableReference; // If the assignment value is a variable reference, this holds that reference
}

export interface WaitNode extends ProgramNode {
    type: NodeType.WAIT;
    parameters: {
        type: 'time' | 'signalInput' | 'expression';
        time?: TabInputModel<Time>;
        signalInput?: WaitNodeSignalInput;
        expression?: TabInputValue;
        reference?: WaitNodeVariableReference;
    };
}
