/**
 * Legacy enumeration for symbol kinds used by the original `URSymbol` abstraction.
 *
 * DEPRECATION: The symbol system has been replaced with dedicated declaration/reference
 * types and description interfaces found under `@universal-robots/contribution-api/types/symbols`.
 * Migrate to:
 *  - Variable: {@link VariableDeclaration}, {@link VariableReference}, {@link VariableDescription}
 *  - Function: {@link FunctionDeclaration}, {@link FunctionReference}, {@link FunctionDescription}
 *  - Module: {@link ModuleDeclaration}, {@link ModuleReference}, {@link ModuleDescription}
 *  - Logic program functionality is now exposed through {@link ProgramNodeMetadata program node metadata} rather than a standalone symbol.
 *
 * This enum remains only for backwards compatibility of existing extensions. Do not use it in new code.
 * @deprecated Use the specific declaration/reference types exported from `@universal-robots/contribution-api/types/symbols`.
 */
export enum URSymbolType {
    Variable = '$$Variable',
    Function = '$$Function',
    Module = '$$Module',
    /** @experimental */
    LogicProgram = '$$LogicProgram',
}

/**
 * Legacy base class for all symbol entities from the original symbol model.
 *
 * DEPRECATION: The new symbol model uses plain TypeScript interfaces instead of an inheritance
 * hierarchy. Replace usages with the appropriate interface from `@universal-robots/contribution-api/types/symbols`.
 * Example migration:
 *  - `class URVariable extends URSymbol { ... }` -> use {@link VariableDeclaration} for declarations and
 *    store runtime state in {@link VariableDescription}.
 *  - Type guards should be replaced by the new interface-specific guards (e.g. `isVariableDeclaration`).
 *
 * @deprecated Use interface based declarations and references from `types/symbols`.
 */
export abstract class URSymbol {
    readonly type!: URSymbolType;
    name: string;
    reference?: boolean;
    declaredByID?: string;
    suppressed?: boolean;
    /**
     *  Create new URSymbol
     * @param name
     * @param reference
     */
    constructor(name: string, reference = false) {
        this.name = name;
        this.reference = reference;
    }
}

/**
 * Legacy variable class used for discovering variables in tree node parameters.
 *
 * REPLACEMENT: Use the variable interfaces exported from
 * `@universal-robots/contribution-api/types/symbols`:
 *  - {@link VariableDeclaration} to represent a declared variable
 *  - {@link VariableReference} to reference an existing variable
 *  - {@link VariableDescription} (and {@link VariableDescriptionWithReference}) for UI/state consumption
 * The allowed value types are now enumerated by `VARIABLE_VALUE_TYPES` instead of {@link VariableValueType}.
 *
 * MIGRATION AID: To convert legacy `URVariable` objects to the new model, invoke the
 * variable upgrade endpoint (`upgradeURVariable`). It returns either an existing
 * {@link VariableDescriptionWithReference} for variable references, or a new
 * {@link VariableDeclaration} for variable declarations.
 *
 * @deprecated Use the variable interfaces & constants from `types/symbols/variable`.
 */
export class URVariable extends URSymbol {
    override readonly type = URSymbolType.Variable;
    valueType?: VariableValueType;
    /**
     *  Create new URVariable
     * @param name
     * @param valueType
     * @param reference
     */
    constructor(name: string, valueType?: VariableValueType, reference = false) {
        super(name, reference);
        this.valueType = valueType;
    }
}

/**
 * Legacy enum describing variable value types.
 *
 * REPLACEMENT: Use the `VARIABLE_VALUE_TYPES` constant array from
 * `@universal-robots/contribution-api/types/symbols/variable` and narrow with `typeof VARIABLE_VALUE_TYPES[number]`.
 *
 * @deprecated Use `VARIABLE_VALUE_TYPES` instead.
 */
export enum VariableValueType {
    BOOLEAN = 'boolean',
    FLOAT = 'float',
    INTEGER = 'integer',
    POSE = 'pose',
    STRING = 'string',
    MATRIX = 'matrix',
    ARRAY = 'array',
    WAYPOINT = 'waypoint',
    GRID = 'grid',
    FRAME = 'frame',
    TIMER = 'timer',
    PROFILE = 'profile',
}

/**
 * Definition of Logic Program
 * @experimental
 */
export class URLogicProgram extends URSymbol {
    override readonly type = URSymbolType.LogicProgram;
}

/**
 * Legacy function symbol class.
 *
 * REPLACEMENT: Use {@link FunctionDeclaration}, {@link FunctionReference}, {@link FunctionDescription}, and
 * {@link FunctionDescriptionWithReference} from `@universal-robots/contribution-api/types/symbols/function`.
 * Module ownership metadata is available via `moduleMetadata` on {@link FunctionDescription}.
 *
 * @deprecated Use the function interfaces from `types/symbols/function`.
 */
export class URFunction extends URSymbol {
    override readonly type = URSymbolType.Function;
}

/**
 * Legacy module symbol class.
 *
 * REPLACEMENT: Use {@link ModuleDeclaration}, {@link ModuleReference}, {@link ModuleDescription}, and
 * {@link ModuleDescriptionWithReference} from `@universal-robots/contribution-api/types/symbols/module`.
 *
 * @deprecated Use the module interfaces from `types/symbols/module`.
 */
export class URModule extends URSymbol {
    override readonly type = URSymbolType.Module;
}

/**
 * Legacy type guard for any `URSymbol` instance.
 *
 * MIGRATION NOTE: The new symbol system does not have a single root type; instead you work directly
 * with distinct declaration/reference/description interfaces (e.g. {@link VariableDeclaration}, {@link FunctionReference}).
 * Refactor logic that depends on a common base class to instead branch on the presence of the new
 * discriminator properties (like `_IDENTIFIER`) or on known interface shapes. Do not attempt a 1:1 guard replacement.
 *
 * @deprecated Refactor to use the new interface-based symbols; remove broad symbol guards.
 */
export function isURSymbol(item: any): item is URSymbol {
    return (
        !!item &&
        Object.prototype.hasOwnProperty.call(item, 'name') &&
        Object.prototype.hasOwnProperty.call(item, 'type') &&
        Object.values(URSymbolType).includes(item.type)
    );
}

/**
 * Legacy variable symbol guard.
 *
 * MIGRATION NOTE: The new model distinguishes between declarations, references and descriptions.
 * Replace code that relies on this broad guard with explicit handling of these separate interfaces
 * (e.g. {@link VariableDeclaration}, {@link VariableReference}, {@link VariableDescription}).
 * There is no direct one-to-one API replacement for this guard.
 *
 * @deprecated Refactor to use `VariableDeclaration` / `VariableReference` / `VariableDescription` interfaces.
 */
export function isVariable(item: any): item is URVariable {
    return isURSymbol(item) && item.type === URSymbolType.Variable;
}

/**
 * Legacy function symbol guard.
 *
 * MIGRATION NOTE: Refactor to the dedicated {@link FunctionDeclaration}, {@link FunctionReference}, and
 * {@link FunctionDescription} interfaces. There is no single guard that covers all cases.
 *
 * @deprecated Remove usage; adopt new function interfaces and their specific guards where needed.
 */
export function isFunction(item: any): item is URFunction {
    return isURSymbol(item) && item.type === URSymbolType.Function;
}

/**
 * Legacy module symbol guard.
 *
 * MIGRATION NOTE: Refactor to distinct {@link ModuleDeclaration}, {@link ModuleReference}, and description interfaces.
 * Do not substitute a single new guard; use the appropriate interface shapes directly.
 *
 * @deprecated Remove usage; branch on new module interfaces instead.
 */
export function isModule(item: any): item is URModule {
    return isURSymbol(item) && item.type === URSymbolType.Module;
}

/**
 * TypeGuard to verify whether a given object is a logic program
 * @param item The item to be interrogated
 * @experimental
 */
export function isLogicProgram(item: any): item is URLogicProgram {
    return isURSymbol(item) && item.type === URSymbolType.LogicProgram;
}

/**
 * Legacy mapping from module names to lists of function symbols.
 *
 * REPLACEMENT: Consider aggregating `FunctionDeclaration` objects keyed by their parent module name, or
 * deriving module/function relationships via `moduleMetadata` on `FunctionDescription`.
 *
 * @deprecated Replace with a record keyed by module name whose values are `FunctionDeclaration[]` or derived descriptions.
 */
export type FunctionsMap = Record<string, URFunction[]>;

/**
 * Definition of the global variable type
 */
export type GlobalVariable = {
    name: string;
    value: string;
};
