import { Observable } from 'rxjs';
import { EventTargetOrCommChannel, MessageInvokerService } from '../message-invoker';

/**
 * @experimental
 */
export const LOGIC_PROGRAM_EXECUTION_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.LogicProgramExecutionService.';

/**
 * Service that handles logic program execution
 * @experimental
 */
export class LogicProgramExecutionService extends MessageInvokerService {
    /**
     * @constructor
     * @param eventTarget
     */
    constructor(override readonly eventTarget: EventTargetOrCommChannel) {
        super(LOGIC_PROGRAM_EXECUTION_SERVICE_MESSAGE_TYPE_BASE, eventTarget);
    }

    /**
     * Start the logic program
     * @experimental
     */
    async startProgram(): Promise<void> {
        return this.postAndAwait('startProgram');
    }

    /**
     * Pause the logic program
     * @experimental
     */
    async pauseProgram(): Promise<void> {
        return this.postAndAwait('pauseProgram');
    }

    /**
     * Resume the logic program
     * @experimental
     */
    async resumeProgram(): Promise<void> {
        return this.postAndAwait('resumeProgram');
    }

    /**
     * Stop the logic program
     * @experimental
     */
    async stopProgram(): Promise<void> {
        return this.postAndAwait('stopProgram');
    }

    /**
     * Get the Logic Program status
     * @experimental
     */
    getProgramStatus(): Observable<string> {
        return this.postAndObserve('getStatus');
    }
}
