import { CommonSymbolDescription } from './common';

export const MODULE_DECLARATION_IDENTIFIER = 'ModuleDeclaration' as const;
export const MODULE_REFERENCE_IDENTIFIER = 'ModuleReference' as const;

/**
 * Describes the current state of a module for use in the UI. Objects of this type should be treated as immutable and should not be saved as its properties are subject to external changes.
 */
export type ModuleDescription = CommonSymbolDescription;

/**
 * Module declaration
 * Use this type to store module declarations
 */
export interface ModuleDeclaration {
    id: string;
    name: string;
    /** Optional description text */
    description?: string;
    _IDENTIFIER: typeof MODULE_DECLARATION_IDENTIFIER;
}

/**
 * Module reference.
 * Use this type to store references to modules
 */
export interface ModuleReference {
    id: string;
    _IDENTIFIER: typeof MODULE_REFERENCE_IDENTIFIER;
}

/**
 * Type for module description and a reference
 * Holds a combined object @type ModuleDescription with extended @type ModuleReference property "reference"
 */
export type ModuleDescriptionWithReference = ModuleDescription & { reference: ModuleReference };

/**
 * ModuleReference guard function
 */
export const isModuleReference = (entity: unknown): entity is ModuleReference => {
    return (
        !!entity &&
        typeof entity === 'object' &&
        Object.hasOwn(entity, 'id') &&
        Object.hasOwn(entity, '_IDENTIFIER') &&
        (entity as { _IDENTIFIER: unknown })._IDENTIFIER === MODULE_REFERENCE_IDENTIFIER
    );
};

/**
 * ModuleDeclaration guard function
 */
export const isModuleDeclaration = (entity: unknown): entity is ModuleDeclaration => {
    return (
        !!entity &&
        typeof entity === 'object' &&
        Object.hasOwn(entity, 'id') &&
        Object.hasOwn(entity, 'name') &&
        Object.hasOwn(entity, '_IDENTIFIER') &&
        (entity as { _IDENTIFIER: unknown })._IDENTIFIER === MODULE_DECLARATION_IDENTIFIER
    );
};
