import { CommonSymbolDescription, ModuleMetadata } from './common';

export const FUNCTION_DECLARATION_IDENTIFIER = 'FunctionDeclaration' as const;
export const FUNCTION_REFERENCE_IDENTIFIER = 'FunctionReference' as const;

/**
 * Describes the current state of a function for use in the UI. Objects of this type should be treated as immutable and should not be saved as its properties are subject to external changes.
 */
export interface FunctionDescription extends CommonSymbolDescription {
    moduleMetadata: ModuleMetadata; // metadata about the module that this function belongs to
}

/**
 * Function declaration
 * Use this type to store function declarations.
 * This is a special type of object that is picked up by the internal function tracking system of PolyScope X and should not be created manually.
 */
export interface FunctionDeclaration {
    id: string;
    name: string;
    _IDENTIFIER: typeof FUNCTION_DECLARATION_IDENTIFIER;
}

/**
 * Function reference.
 * Use this type to store references to functions
 */
export interface FunctionReference {
    id: string;
    _IDENTIFIER: typeof FUNCTION_REFERENCE_IDENTIFIER;
}

/**
 * Function description and a reference
 * Holds a combined object @type FunctionDescription with extended @type FunctionReference property "reference"
 */
export type FunctionDescriptionWithReference = FunctionDescription & { reference: FunctionReference };

/**
 * FunctionReference guard function
 */
export const isFunctionReference = (entity: unknown): entity is FunctionReference => {
    return (
        !!entity &&
        typeof entity === 'object' &&
        Object.hasOwn(entity, 'id') &&
        Object.hasOwn(entity, '_IDENTIFIER') &&
        (entity as { _IDENTIFIER: unknown })._IDENTIFIER === FUNCTION_REFERENCE_IDENTIFIER
    );
};

/**
 * FunctionDescriptionWithReference guard function
 * @param entity
 * @returns
 */
export const isFunctionDescriptionWithReference = (entity: unknown): entity is FunctionDescriptionWithReference => {
    return (
        !!entity &&
        typeof entity === 'object' &&
        Object.hasOwn(entity, 'name') &&
        Object.hasOwn(entity, 'reference') &&
        isFunctionReference((entity as { reference: unknown }).reference)
    );
};

/**
 * FunctionDeclaration guard function
 */
export const isFunctionDeclaration = (entity: unknown): entity is FunctionDeclaration => {
    return (
        !!entity &&
        typeof entity === 'object' &&
        Object.hasOwn(entity, 'id') &&
        Object.hasOwn(entity, 'name') &&
        Object.hasOwn(entity, '_IDENTIFIER') &&
        (entity as { _IDENTIFIER: unknown })._IDENTIFIER === FUNCTION_DECLARATION_IDENTIFIER
    );
};
