/**
 * VariableScope enum
 * Defines the scope for variable declarations/assignment in URScript
 */
export enum VariableScope {
    /**
     * No prefix - assigns to an existing variable
     */
    NONE = 'none',
    /**
     * Local variable scope - prefix with 'local'
     */
    LOCAL = 'local',
    /**
     * Shared variable scope - prefix with 'shared'
     */
    SHARED = 'shared',
    /**
     * Global variable scope - prefix with 'global'
     */
    GLOBAL = 'global',
}
