import { Object3D, Texture, Material, BufferGeometry, BufferAttribute, Object3DJSON, InterleavedBufferAttribute } from 'three';
import { Serializer } from '../message-invoker';

/**
 *  A null serializer that simply outputs the object as is.
 */
export class NullSerializer implements Serializer {
    /**
     * Serialize the object as is.
     * @param serializerType The type of serializer to use.
     * @param obj The object to serialize.
     * @returns The serialized object.
     */
    public serialize(serializerType: string, obj: any): { serializerType: string; serializedObject: any; transferables: Transferable[] } {
        return {
            serializerType,
            serializedObject: obj,
            transferables: [],
        };
    }
}

/**
 * Typed numerical array that can be used for serializing and deserializing 3D objects
 * It can be of the following types:
 * - Int8Array
 * - Uint8Array
 * - Uint8ClampedArray
 * - Int16Array
 * - Uint16Array
 * - Int32Array
 * - Uint32Array
 * - Float32Array
 * - Float64Array
 */
export type TypedArray =
    | Int8Array
    | Uint8Array
    | Uint8ClampedArray
    | Int16Array
    | Uint16Array
    | Int32Array
    | Uint32Array
    | Float32Array
    | Float64Array;

/**
 * Metadata for scene object storage buffers
 */
interface BufferMetadata {
    /**
     * The type of the array.
     */
    type: string;
    /**
     * The byte offset of the array.
     */
    byteOffset: number;
    /**
     * The item size of the array.
     */
    itemSize: number;
    /**
     * The length of the array.
     */
    length: number;
    /**
     * Whether the array is normalized.
     */
    normalized: boolean;
    /**
     * The index of the buffer.
     */
    bufferIndex: number;
}

/**
 * Map of buffer metadata for each owner UUID
 */
interface BufferMetadataMap {
    /**
     * The owner UUID.
     */
    [ownerUUID: string]: {
        /**
         * The property key.
         */
        [propertyKey: string]: BufferMetadata;
    };
}

/**
 * Map of attribute IDs for each owner UUID
 */
interface AttributeMap {
    /**
     * The owner UUID.
     */
    [key: string]: {
        /**
         * The property key and numerical value of the attribute id
         */
        [key: string]: number;
    };
}

/**
 * Texture image type
 */
interface TextureImageType {
    /**
     * The type of the texture image.
     */
    type: 'image';
    /**
     * The image bitmap.
     */
    imageBitmap: ImageBitmap;
}

/**
 *  Typed texture data structure
 */
interface TextureDataType {
    /**
     * The type of the texture data.
     */
    type: 'data';
    /**
     * The index of the buffer.
     */
    bufferIndex: number;
    /**
     * The width of the texture.
     */
    width: number;
    /**
     * The height of the texture.
     */
    height: number;
    /**
     * The depth of the texture.
     */
    depth: number;
    /**
     * The type of the array.
     */
    arrayType: string;
    /**
     * The byte offset of the array.
     */
    byteOffset: number;
    /**
     * The length of the array.
     */
    length: number;
}

/**
 * Texture array type
 */
interface TextureArrayType {
    /**
     * The type of the texture array.
     */
    type: 'array';
    /**
     * The elements of the texture array.
     */
    elements: Array<TextureImageType | TextureDataType>;
}

/**
 * Map of texture sources for each texture indexed by texture UUID
 */
interface TextureSourceMap {
    /**
     * The texture UUID.
     */
    [key: string]: TextureImageType | TextureDataType | TextureArrayType;
}

/**
 * Holds a Serialized 3D Object
 */
export interface SerializedObject3D {
    /**
     * The JSON object.
     */
    json: Object3DJSON;
    /**
     * The array of array buffers.
     */
    arrayBuffers: ArrayBufferLike[];
    /**
     * The buffer metadata.
     */
    bufferMetadata: BufferMetadataMap;
    /**
     * The attribute map.
     */
    attributeMap: AttributeMap;
    /**
     * The texture sources.
     */
    textureSources: TextureSourceMap;
}

/**
 * Serialize a three.js object as a JSON object and an array of array buffers.
 * @param serializedObject3D The object to serialize.
 * @returns The serialized object. and an array of serialized transferables
 */
function serializeObject(object: Object3D): {
    serializedObject3D: SerializedObject3D;
    transferables: Transferable[];
} {
    const result = {
        serializedObject3D: {
            json: {} as Object3DJSON,
            arrayBuffers: [] as ArrayBufferLike[],
            bufferMetadata: {} as BufferMetadataMap,
            attributeMap: {} as AttributeMap,
            textureSources: {} as TextureSourceMap,
        },
        transferables: [] as Transferable[],
    };

    const bufferMap = new Map<ArrayBufferLike, number>();

    const MIN_TRANSFER_SIZE = 10;

    /**
     * Replace array with descriptor for any TypedArray found
     */
    const replaceArrayWithDescriptor = (ownerUUID: string, propertyKey: string, attr: any) => {
        const array = attr.array;
        if (!ArrayBuffer.isView(array)) return;

        const typed = array as TypedArray;

        if (typed.byteLength < MIN_TRANSFER_SIZE) {
            return;
        }

        let bufferIndex = bufferMap.get(array.buffer);
        if (bufferIndex === undefined) {
            bufferIndex = result.serializedObject3D.arrayBuffers.length;
            bufferMap.set(array.buffer, bufferIndex);
            result.serializedObject3D.arrayBuffers.push(array.buffer);
            result.transferables.push(array.buffer);
        }

        if (!result.serializedObject3D.bufferMetadata[ownerUUID]) {
            result.serializedObject3D.bufferMetadata[ownerUUID] = {};
        }

        result.serializedObject3D.bufferMetadata[ownerUUID][propertyKey] = {
            type: array.constructor.name,
            byteOffset: array.byteOffset,
            itemSize: attr.itemSize,
            length: typed.length,
            normalized: attr.normalized,
            bufferIndex,
        };

        attr.array = new Int8Array();
    };

    /**
     * Process and serialized a single texture image.
     * If the image has been seen before, it will be returned as a descriptor.
     * @param texture The texture to process.
     * @returns The descriptor for the texture.
     */
    const processSingleTexture = (texture: any) => {
        if (texture.image instanceof ImageBitmap) {
            const bitmap = texture.image as ImageBitmap;
            result.transferables.push(bitmap);
            texture.image = { src: 'data:/' };
            return {
                type: 'image' as const,
                imageBitmap: bitmap,
            };
        }

        const maybeData = texture.image?.data;
        if (maybeData && ArrayBuffer.isView(maybeData)) {
            const typed = maybeData as TypedArray;
            let bufferIndex = bufferMap.get(typed.buffer);
            if (bufferIndex === undefined) {
                bufferIndex = result.serializedObject3D.arrayBuffers.length;
                bufferMap.set(typed.buffer, bufferIndex);
                result.serializedObject3D.arrayBuffers.push(typed.buffer);
                result.transferables.push(typed.buffer);
            }
            const descriptor = {
                type: 'data' as const,
                bufferIndex,
                width: texture.image.width,
                height: texture.image.height,
                depth: texture.image.depth,
                arrayType: (typed as any).constructor.name,
                byteOffset: typed.byteOffset,
                length: typed.length,
            };
            texture.image = { data: new Int8Array(), width: 0, height: 0 };
            return descriptor;
        }

        return null;
    };

    /**
     * Replaces the texture image with a descriptor. This allows texture images to be stored and serialized
     * only once, and then referenced by the descriptor.
     * @param texture The texture to replace.
     * @param seenTextures The set of textures that have already been seen.
     * @returns True if the texture was replaced, false otherwise.
     */
    function replaceTextureImageWithDescriptor(texture: Texture, seenTextures: Set<Texture>) {
        if (!texture.image) {
            return false;
        }

        if (seenTextures.has(texture)) {
            return true;
        }

        if (Array.isArray(texture.image)) {
            const elements: any[] = [];
            for (const textureElement of texture.image) {
                const descriptor = processSingleTexture(textureElement);
                if (descriptor) {
                    elements.push(descriptor);
                }
            }
            if (elements.length > 0) {
                result.serializedObject3D.textureSources[texture.uuid] = {
                    type: 'array',
                    elements,
                };
            }
        } else {
            const single = processSingleTexture(texture);
            if (single) {
                result.serializedObject3D.textureSources[texture.uuid] = single as any;
            }
        }

        seenTextures.add(texture);
        return true;
    }

    result.serializedObject3D.attributeMap = generateAttributeMap(object);

    const seenGeometries = new Set<BufferGeometry>();
    const seenAttributes = new Set<BufferAttribute | InterleavedBufferAttribute>();
    const seenTextures = new Set<Texture>();

    /**
     *  serializes the buffer geometry and its attributes.
     */
    const serializeGeometry = (geometry: BufferGeometry) => {
        for (const key in geometry.attributes) {
            const attribute = geometry.attributes[key];

            if (seenAttributes.has(attribute)) {
                return;
            }
            seenAttributes.add(attribute);

            replaceArrayWithDescriptor(geometry.uuid, key, attribute);
        }

        if (geometry.index && geometry.index.array && geometry.index.array.length > 0 && !seenAttributes.has(geometry.index)) {
            const index = geometry.index;
            seenAttributes.add(index);

            replaceArrayWithDescriptor(geometry.uuid, 'index', index);
        }
    };

    /**
     *
     */
    const serializeMaterial = (material: Material) => {
        const materials = Array.isArray(material) ? material : [material];
        materials.forEach((mat: Material) => {
            Object.keys(mat).forEach((key) => {
                const texture = (mat as any)[key];
                if (texture?.isTexture) {
                    replaceTextureImageWithDescriptor(texture, seenTextures);
                }
            });
        });
    };

    object.traverse((obj) => {
        const geometry = (obj as any).geometry;
        if (geometry instanceof BufferGeometry && !(geometry as any).parameters) {
            if (seenGeometries.has(geometry)) {
                return;
            }
            seenGeometries.add(geometry);
            serializeGeometry(geometry);
        }

        const material = (obj as any).material;
        if (material) {
            serializeMaterial(material);
        }
    });

    result.serializedObject3D.json = object.toJSON();

    return result;
}

/**
 *  Generate the attribute map for a 3D object. This accumulates all
 *  attributes for the geometry and index buffers.
 *
 * @param object The object to generate the attribute map for.
 * @returns The attribute map.
 */
function generateAttributeMap(object: Object3D): AttributeMap {
    const attributeMap: AttributeMap = {};
    object.traverse((obj) => {
        const geometry = (obj as any).geometry;
        if (geometry instanceof BufferGeometry && !(geometry as any).parameters) {
            for (const key in geometry.attributes) {
                const attribute = geometry.attributes[key];

                if (!attributeMap[geometry.uuid]) {
                    attributeMap[geometry.uuid] = {};
                }

                attributeMap[geometry.uuid][key] = attribute.id;
            }

            if (geometry.index) {
                if (!attributeMap[geometry.uuid]) {
                    attributeMap[geometry.uuid] = {};
                }
                attributeMap[geometry.uuid]['index'] = geometry.index.id;
            }
        }
    });

    return attributeMap;
}

/**
 * Serializer for a three.js object that serializes the object as a JSON object and an array of array buffers.
 *
 */
export class Object3DJsonAndArrayBuffersSerializer implements Serializer {
    /**
     * Serialize the object as a JSON object and an array of array buffers.
     * @param serializerType The type of serializer to use.
     * @param obj The object to serialize.
     */
    public serialize(
        serializerType: string,
        obj: any,
    ): {
        serializerType: string;
        serializedObject: SerializedObject3D;
        transferables: Transferable[];
    } {
        const { serializedObject3D, transferables } = serializeObject(obj);

        return {
            serializerType,
            serializedObject: serializedObject3D,
            transferables: transferables,
        };
    }
}
