import { SignalAnalogDomainValueEnum } from '../../../sources';
import { Voltage } from '../../../values';

/**
 * An identifier for controlling the Tool I/O
 * The id should not change, and can be persisted as part of the application
 */
export interface ToolController {
    id: string;
    name: string;
}

/**
 * For grouping tool controllers
 */
export interface CategorizedToolController extends ToolController {
    applicationNodeType: string;
    vendorName: string;
}

/**
 * Power output
 */
export enum PowerOutputEnum {
    DISABLED,
    SINKING,
    SOURCING,
    PUSH_PULL,
}

/**
 * Tool output
 */
export type ToolOutput = {
    dualPinPower: boolean;
    voltage: Voltage;
    powerOutput: Record<string, PowerOutputEnum>;
};

/**
 * Baud rate
 */
export enum BaudRateEnum {
    BAUD_9600 = '9600',
    BAUD_19200 = '19200',
    BAUD_38400 = '38400',
    BAUD_57600 = '57600',
    BAUD_115200 = '115200',
    BAUD_1M = '1000000',
    BAUD_2M = '2000000',
    BAUD_5M = '5000000',
}

/**
 * Parity
 */
export enum ParityEnum {
    NONE,
    ODD,
    EVEN,
}

/**
 * Stop Bits
 */
export enum StopBitsEnum {
    ONE = 1,
    TWO = 2,
}

/**
 * Tool Communication
 */
export interface ToolCommunication {
    enabled: boolean;
    baudRate: BaudRateEnum;
    parity: ParityEnum;
    stopBits: StopBitsEnum;
    rxIdleChars: number;
    txIdleChars: number;
}

/**
 * Tool Control
 */
export interface ToolControl {
    toolAnalogDomainMap?: Record<string, SignalAnalogDomainValueEnum>;
    toolCommunication?: ToolCommunication;
    toolOutput?: ToolOutput;
}
