import { Frame } from '../..';
import { Expression } from '../../../common';
import { VariableDeclaration, VariableReference } from '../../../symbols/variable';
import { Pose } from '../../models/program';
import { ProgramNode } from '../../program.node';
import { NodeType } from './program-node-type';

export interface FrameNode extends ProgramNode {
    type: NodeType.FRAME;
    parameters: FrameNodeParameters;
}

export interface FrameNodeParameters {
    // Selected action for frame manipulation - Create, Move, Delete, Change parent
    action?: FrameNodeAction;
    // Target frame for selected action
    actionFrame?: NodeParameterFrame;
    // Target position for Move action or Create action
    targetPosition?: Pose;
    targetPositionByExpression?: Expression;
    // Target parent name for Change parent, Create or Move action
    parentTarget?: NodeParameterFrame;
}

export type FrameType = 'frame' | 'variableReference' | 'variableDeclaration' | 'string';

export interface NodeParameterFrame {
    type: FrameType;
    frame?: Frame;
    variableReference?: VariableReference;
    variableDeclaration?: VariableDeclaration;
    liveFrameName?: string;
}

export enum FrameNodeAction {
    CREATE = 'create',
    MOVE = 'move',
    DELETE = 'delete',
    CHANGE_PARENT = 'change-parent',
}
