import { AddBlockChildNode, AddNode, ProgramType, RemoveNode, SubtreeContext, SubtreeNode, TreeContext } from '../../types/context';
import { ProgramNode } from '../../types/nodes';
import { EventTargetOrCommChannel, MessageInvokerService } from '../message-invoker';

export const PROGRAM_TREE_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.ProgramTreeService.';

/**
 * Service that handles node insertion and removal of nodes
 */
export class ProgramTreeService extends MessageInvokerService {
    /**
     * @constructor
     * @param eventTarget
     */
    constructor(override readonly eventTarget: EventTargetOrCommChannel) {
        super(PROGRAM_TREE_SERVICE_MESSAGE_TYPE_BASE, eventTarget);
    }

    /**
     * Update a specific node in the program tree using the given nodes id
     * @param node Node to be updated
     */
    async updateSubTreeNode(node: SubtreeNode): Promise<void> {
        return this.postAndAwait('updateSubTreeNode', { node: node.node, id: node.id });
    }

    /**
     * Update child node
     * @param node Child node to be updated
     * @deprecated Use {@link updateSubTreeNode} instead
     */
    async updateChildNode(node: SubtreeNode): Promise<void> {
        return this.postAndAwait('updateChildNode', node);
    }

    /**
     * Add node as either child or sibling
     * @param node node to be added
     */
    async addNode(node: AddNode): Promise<void> {
        return this.postAndAwait('addNode', node);
    }

    /**
     * Add a node to the root of a program block, for example the main program or
     * the before start
     * @param The node, and other add parameters
     */
    async addBlockChildNode(node: AddBlockChildNode): Promise<void> {
        return this.postAndAwait('addBlockChildNode', node);
    }

    /**
     * Remove child node
     * @param node Child node to be removed
     */
    async removeChildNode(node: RemoveNode): Promise<void> {
        return this.postAndAwait('removeChildNode', node);
    }

    /**
     * Sets the given node as the active program block
     * @param nodeID The node to navigate to
     */
    setActiveProgramBlock(nodeID: string): Promise<void> {
        return this.postAndAwait('setActiveProgramBlock', nodeID);
    }

    /**
     * Sets the given node as the active program block
     * @param nodeID The node to navigate to
     */
    selectProgramNode(nodeID: string): Promise<void> {
        return this.postAndAwait('selectProgramNode', nodeID);
    }

    /**
     * Get a readonly version of a given node
     * @param nodeID The node to get
     */
    getProgramNodeById(nodeID: string): Promise<Readonly<ProgramNode>> {
        return this.postAndAwait('getProgramNodeById', nodeID);
    }

    /**
     * Get the tree context from a given program node
     */
    getTreeContextFromProgramNodeById(subTreeNodeId: string): Promise<TreeContext> {
        return this.postAndAwait('getTreeContextFromProgramNodeById', { subTreeNodeId });
    }

    /**
     * Get the subtree context from a given program node.
     * This returns the same traversals as getTreeContextFromProgramNodeById but will
     * return a SubtreeNode for ancestor and sibling calls.
     * For ancestor and sibling calls, where a SubtreeNode is not from the calling URCap,
     * then the SubtreeNode id will be ''.
     */
    getSubtreeContextFromProgramNodeById(subTreeNodeId: string): Promise<SubtreeContext> {
        return this.postAndAwait('getSubtreeContextFromProgramNodeById', { subTreeNodeId });
    }

    /**
     * Returns all instances of this URCap's contributed nodes currently in the program tree.
     *
     * @param programType Filter by program type. Undefined (default) or MAIN returns main program nodes, LOGIC returns logic program nodes.
     * @returns Array of SubtreeNode objects with node ID and readonly node data
     */
    getContributedNodeInstancesForURCap(programType?: ProgramType): Promise<SubtreeNode[]> {
        return this.postAndAwait('getContributedNodeInstancesForURCap', { programType });
    }

    /**
     * Reverts the last action performed in the program tree.
     * @returns {void} A promise that resolves when the undo operation is complete.
     */
    undo(): Promise<void> {
        return this.postAndAwait('undo');
    }

    /**
     * Checks if an undo operation can be performed.
     * @returns A promise that resolves to a boolean indicating if undo is possible.
     */
    canUndo(): Promise<boolean> {
        return this.postAndAwait('canUndo');
    }

    /**
     * Reapplies the last action that was undone in the program tree.
     * @returns {void} A promise that resolves when the redo operation is complete.
     */
    redo(): Promise<void> {
        return this.postAndAwait('redo');
    }

    /**
     * Checks if a redo operation can be performed.
     * @returns A promise that resolves to a boolean indicating if redo is possible.
     */
    canRedo(): Promise<boolean> {
        return this.postAndAwait('canRedo');
    }
}
