import { ProgramType } from '../types/context/program.context';

/**
 * @internal Request-scoped validation context holder for worker threads.
 * Stores the programType for the currently executing validator.
 */

let currentProgramType: ProgramType | undefined = undefined;

/** @internal Sets the context for the current validation execution. */
export function setValidationContext(context: { programType: ProgramType } | null): void {
    currentProgramType = context?.programType ?? undefined;
}

/** @internal Gets the programType from the current context. */
export function getProgramTypeFromContext(): ProgramType | undefined {
    return currentProgramType ?? undefined;
}
