import { Observable } from 'rxjs';
import { URModule } from '../../types/nodes';
import { ModuleDeclaration, ModuleDescription, ModuleDescriptionWithReference, ModuleReference } from '../../types/symbols';
import { EventTargetOrCommChannel, MessageInvokerService } from '../message-invoker';

export const MODULE_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.module-service.';

/**
 * Options for the modules endpoint
 */
export interface ModulesOptions {
    /**
     * If true, includes deleted modules with isDeleted flag set to true
     */
    includeDeleted?: boolean;
}

/**
 * Service for interacting with modules
 */
export class ModuleService extends MessageInvokerService {
    /**
     * Create a service for the specific worker
     * @param eventTarget
     */
    constructor(override readonly eventTarget: EventTargetOrCommChannel) {
        super(MODULE_SERVICE_MESSAGE_TYPE_BASE, eventTarget);
    }

    /**
     * Get a list of available modules
     * @param options Optional settings for the query
     * @param options.includeDeleted If true, includes deleted modules with isDeleted flag set
     */
    modules(options?: ModulesOptions): Observable<Array<ModuleDescriptionWithReference>> {
        return this.postAndObserve('modules', options);
    }

    /**
     * Create a new module declaration
     * @param name Actual name of the module. Might be changed by the service to avoid name clashes
     * @returns Promise resolving to the created module declaration
     */
    async createModule(name: string): Promise<ModuleDeclaration> {
        return this.postAndAwait('createModule', { name });
    }

    /**
     * Get a module description from its reference
     * @param reference the module reference
     * @returns Promise resolving to the module description or undefined if not found
     */
    async getModuleDescription(reference: ModuleReference): Promise<ModuleDescription | undefined> {
        return this.postAndAwait('getModuleDescription', { reference });
    }
    /**
     * Upgrade from URModule to ModuleDeclaration | ModuleReference.
     * If a module with the property reference=true is provided, the corresponding ModuleReference is returned.
     * If a module with reference=false is provided, a ModuleDeclaration is returned.
     * @param module URModule to upgrade
     * @returns Promise resolving to the ModuleDeclaration | ModuleReference | undefined if not found
     */
    async upgradeURModule<T extends ModuleDeclaration | ModuleReference>(module: URModule): Promise<T | undefined> {
        return this.postAndAwait('upgradeURModule', { module });
    }
}
