import { Observable } from 'rxjs';
import { ProgramType } from '../../types/context/program.context';
import {
    FunctionsMap,
    GlobalVariable,
    URFunction,
    URLogicProgram,
    URModule,
    URSymbolType,
    URVariable,
    VariableValueType,
} from '../../types/nodes';
import { EventTargetOrCommChannel, MessageInvokerService } from '../message-invoker';

export const SYMBOL_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.SymbolService.';

/**
 * Service for generating and getting reserved variable names
 * @deprecated Use dedicated services instead: `VariableService`, `FunctionService`, `ModuleService`.
 */
export class SymbolService extends MessageInvokerService {
    /**
     * Create a service for the specific worker
     * @param eventTarget
     * @deprecated Prefer constructing the specific service (e.g. `new VariableService(eventTarget)`).
     */
    constructor(override readonly eventTarget: EventTargetOrCommChannel) {
        super(SYMBOL_SERVICE_MESSAGE_TYPE_BASE, eventTarget);
    }
    /**
     * Get a list of available variables
     * @returns
     * @deprecated Use `VariableService.variables()` to observe variable descriptions.
     */
    getVariables(): Promise<Array<URVariable>> {
        return this.postAndAwait('getVariables', {});
    }
    /**
     * Get an observable of available variables
     * @deprecated Use `VariableService.variables()` which returns richer descriptions including references.
     */
    variables(): Observable<Array<URVariable>> {
        return this.postAndObserve('variables', {});
    }

    /**
     * Returns a list of the global variables as a stream.
     * @returns {Observable<Array<GlobalVariable>>} Observable of global variables object
     * @deprecated Use `VariableService.variables()`; global variables are exposed uniformly via variable descriptions.
     */
    globalVariables(): Observable<Array<GlobalVariable>> {
        return this.postAndObserve('globalVariables', {});
    }

    /**
     * Returns a list of the logic program variables as a stream.
     * @returns {Observable<Array<GlobalVariable>>} Observable of logic program variables object
     * @experimental
     */
    logicProgramVariables(): Observable<Array<GlobalVariable>> {
        return this.postAndObserve('logicProgramVariables', {});
    }

    /**
     * Generates a new variable. The variable name is based on the suggested name.
     * If the suggested name is not usable a new, based on the suggestion, will be created
     *
     * @param suggestedName The intended name for the variable, will be suffixed if the name is already taken
     * @param valueType The ValueType of the variable
     * @param blacklist Optional parameter to provide additional names which shouldn't be used.
     * @deprecated Use `VariableService.createVariable(name, variableType)`; perform your own naming conflict resolution if needed.
     */
    generateVariable(suggestedName: string, valueType: VariableValueType, blacklist?: Array<string>): Promise<URVariable> {
        return this.postAndAwait('generateVariable', {
            suggestedName,
            valueType,
            blacklist,
        });
    }

    /**
     * Return true if the provided name is the name of a registered variable
     *
     * @param variableName
     * @deprecated Use `VariableService.variables()` and search by name; there's no direct registration check helper.
     */
    isRegisteredVariableName(variableName: string): Promise<boolean> {
        return this.postAndAwait('isRegisteredVariableName', { variableName });
    }
    /**
     * Get a list of available functions for the given module name. If no name provided, functions for the global scope
     * @param moduleName
     * @returns
     * @deprecated Use `FunctionService.functions()` then filter by module (description contains module reference).
     */
    getFunctions(moduleName = ''): Promise<URFunction[]> {
        return this.postAndAwait('getFunctions', { moduleName });
    }

    /**
     * Get functions map. Contains a list of functions for each module name. Note: Empty string is the global scope.
     * @param filter Filter on if the function is async or not
     * is async or not
     * @returns
     * @deprecated Prefer querying `FunctionService.functions()` and building maps client-side; async filtering can be applied locally.
     */
    getFunctionsMap(filter?: { filterAsync?: boolean }): Promise<FunctionsMap> {
        return this.postAndAwait('getFunctionsMap', filter);
    }
    /**
     * Generates a new function. The function name is based on the suggested name.
     * If the suggested name is not usable a new, based on the suggestion, will be created
     *
     * @param suggestedName
     * @param moduleName
     * @deprecated Use `FunctionService.createFunction(name)`.
     */
    generateFunction(suggestedName: string, moduleName?: string): Promise<URFunction> {
        return this.postAndAwait('generateFunction', {
            functionName: suggestedName,
            moduleName,
        });
    }

    /**
     * Return true if the provided name is the name of a registered function
     *
     * @param functionName
     * @param moduleName
     * @deprecated Use `FunctionService.functions()` and search for a matching name; no direct registration check helper.
     */
    isRegisteredFunctionName(functionName: string, moduleName?: string): Promise<boolean> {
        return this.postAndAwait('isRegisteredFunctionName', {
            functionName,
            moduleName,
        });
    }

    /**
     * Get a list of available modules
     * @returns
     * @deprecated Use `ModuleService.modules()` for reactive module listing.
     */
    getModuleNames(): Promise<Array<string>> {
        return this.postAndAwait('getModuleNames', {});
    }

    /**
     * Generates a new module. The module name is based on the suggested name.
     * If the suggested name is not usable a new, based on the suggestion, will be created
     *
     * @param suggestedName
     * @deprecated Use `ModuleService.createModule(name)`.
     */
    generateModule(suggestedName: string): Promise<URModule> {
        return this.postAndAwait('generateModule', suggestedName);
    }

    /**
     * Return true if the provided name is the name of a registered module
     *
     * @param moduleName
     * @deprecated Use `ModuleService.modules()` and search by name; no direct registration check helper.
     */
    isRegisteredModuleName(moduleName: string): Promise<boolean> {
        return this.postAndAwait('isRegisteredModuleName', { moduleName });
    }

    /**
     * Return a list of available Logic Program names
     * @returns Promise<Array<string>> A promise that resolves to an array of logic program names.
     * @experimental
     */
    getLogicProgramNames(): Promise<Array<string>> {
        return this.postAndAwait('getLogicProgramNames', {});
    }

    /**
     * Generates a new Logic Program. The program name is based on the suggested name.
     * If the suggested name is not usable a new, based on the suggestion, will be created
     *
     * @param suggestedName
     * @returns Promise\<URLogicProgram\> A promise that resolves to the created logic program.
     * @experimental
     */
    generateLogicProgram(suggestedName: string): Promise<URLogicProgram> {
        return this.postAndAwait('generateLogicProgram', suggestedName);
    }

    /**
     * Returns true if the provided name matches a registered Logic Program.
     *
     * @param logicProgramName The name of the Logic Program to check for registration.
     * @returns Promise<boolean> A promise that resolves to true if the name is registered, otherwise false.
     * @experimental
     */
    isRegisteredLogicProgramName(logicProgramName: string): Promise<boolean> {
        return this.postAndAwait('isRegisteredLogicProgramName', {
            logicProgramName,
        });
    }

    /**
     *  Return true if the provided name is a registered name of the given type.
     * @param name
     * @param type
     * @param moduleName
     * @param unique
     * @returns
     * @deprecated Use the specific service (Variable/Function/Module) and inspect lists for existence; uniqueness checks should be done client-side.
     */
    isRegisteredName(name: string, type: URSymbolType, moduleName?: string, unique = false, programType?: ProgramType): Promise<boolean> {
        return this.postAndAwait('isRegisteredName', {
            name,
            type,
            moduleName,
            unique,
            programType,
        });
    }

    /**
     * Return true if the declaring program node is suppressed
     * @param name The name of the symbol
     * @param moduleName The module of the symbol if defined
     * @return Boolean describing if the declaring node is suppressed
     * @deprecated Suppression is exposed via metadata on objects with the VariableDescription, FunctionDescription and ModuleDescription type. Query entities on the corresponding service (VariableService, FunctionService, ModuleService) and check for the `isSuppressed` property.
     */
    isSuppressed(name: string, moduleName?: string): Promise<boolean> {
        return this.postAndAwait('isSuppressed', { name, moduleName });
    }

    /**
     * Get the URVariable with the given name
     * @return URVariable with the given name
     * @param name Name of the variable to get
     * @deprecated Use `VariableService.getVariableDescription(reference)` once you have a reference; avoid name-based lookups.
     */
    getVariable(name: string): Promise<URVariable | undefined> {
        return this.postAndAwait('getVariable', { name });
    }

    /**
     *
     * @param variableName name of the variable being validated
     * @param acceptedTypes an optional array of valid type strings, e.g., float.
     * @returns true if the variable is registered not suppressed, and is of a valid value type
     * @deprecated Compose validation using `VariableService.variables()` & description metadata instead.
     */
    async isValidVariable(variableName: string, acceptedTypes?: string[]): Promise<boolean> {
        const isRegistered = await this.isRegisteredVariableName(variableName);
        const isSuppressed = await this.isSuppressed(variableName);
        const variable = await this.getVariable(variableName);
        let isOfValidValueType = true;
        if (acceptedTypes) {
            isOfValidValueType = acceptedTypes.some((acceptedType) => acceptedType === variable?.valueType);
        }
        return isRegistered && !isSuppressed && isOfValidValueType;
    }

    /**
     * Returns true if the given function is a thread
     * @param functionName The name of the function
     * @param moduleName The module of the symbol if defined
     * @return Boolean describing if the function is a thread
     * @deprecated Use metadata from `FunctionService.functions()` when async/thread capability is surfaced there.
     */
    isAsyncFunction(functionName: string, moduleName?: string): Promise<boolean> {
        return this.postAndAwait('isAsyncFunction', { functionName, moduleName });
    }
}
