import { Observable } from 'rxjs';
import { Object3D } from 'three';
import { PoseUtils, PoseRepresentation } from '../../types/nodes';
import { ControllerPose, ZUpPositionMeters, ZUpRotationVectorRadians } from '../../types/nodes/models/program/pose.model';
import { CommunicationChannel, MessageInvokerService, Serializer } from '../message-invoker';
import { Object3DJsonAndArrayBuffersSerializer, NullSerializer } from './scene-serializers';
import {
    ConstructorDefinitionAPI,
    ConstructorSignature,
    ConstructorType,
    LayerCommand,
    ParentCommand,
    PropertyCommand,
    SceneObject,
    UuidType,
    VisibleCommand,
    SetConstructorParametersCommand,
    MaterialPropertiesCommand,
    ModifySharedMaterialsCommand,
    ConstructionData,
    PositionCommand,
    PoseCommand,
    RotationCommand,
    MaterialPropertyMap,
} from './scene.model';

export const SCENE_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.SceneService.';

/**
 *
 */
abstract class SceneService extends MessageInvokerService {
    serializers: Map<string, Serializer> = new Map<string, Serializer>();
    /**
     * Gets the serializer for a three.js object.
     * @param threeObject The three.js object to get the serializer for.
     * @returns The serializer for the three.js object.
     */
    abstract getObjectSerializer(threeObject: Object3D): { serializerType: string; object: any };

    private objectConstructors = new Map<string, ConstructorSignature>();

    /**
     * Posts a three.js object to the scene service.
     * @param type The type of object to post.
     * @param threeObject The three.js object to post.
     * @param data The data to post.
     * @returns A promise that resolves when the object has been posted.
     */
    postThreeObject<T>(type: string, threeObject: Object3D, data: any = {}): Promise<T> {
        threeObject.updateMatrixWorld(true);
        return this.communicationChannel.request<T>(
            SCENE_SERVICE_MESSAGE_TYPE_BASE + type,
            {
                ...data,
                serializableObjects: [this.getObjectSerializer(threeObject)],
            },
            this.serializers,
        );
    }

    /**
     * Constructor for the SceneService.
     * @param communicationChannel The communication channel to use to communicate with the scene service.
     */
    constructor(override readonly communicationChannel: CommunicationChannel) {
        super(SCENE_SERVICE_MESSAGE_TYPE_BASE, communicationChannel);
        this.serializers.set('threeJsonAndArrayBuffers', new Object3DJsonAndArrayBuffersSerializer());
        this.serializers.set('none', new NullSerializer());

        this.communicationChannel.addWorkerTrigger('invokeObjectConstructorInWorker', async (event: any) => {
            const { objectUuid, constructionData } = event.data.data;
            const objectConstructor = this.objectConstructors.get(constructionData.constructorName);
            if (!objectConstructor) {
                return;
            }

            const object = await objectConstructor(constructionData);

            const data = {
                objectUuid,
                constructionData: object.constructionData,
                runtimeData: object.runtimeData,
            };

            this.postThreeObject('storeObject', object.object, data);
        });
    }

    /**
     * Defines a constructor for a scene object.
     * @param constructorDefinition The definition of the constructor.
     * @returns A promise that resolves when the constructor has been defined.
     */
    defineConstructor(constructorDefinition: ConstructorDefinitionAPI) {
        const constructorMessageDefinition = {
            constructorName: constructorDefinition.name,
            constructorType: ConstructorType.PARAMETERIZED,
        };
        if (constructorDefinition.parameterizedConstructor) {
            this.objectConstructors.set(constructorDefinition.name, constructorDefinition.parameterizedConstructor);
        }
        return this.request('defineConstructor', { constructorDefinition: constructorMessageDefinition });
    }

    /**
     * Basic implementation, add a non-attached object at the origin in the world frame. Assume
     * the object prototype and the object are one in the same, and no parameters are needed.
     * @param object The object to add.
     * @returns A promise that resolves when the object has been added.
     */
    addNewObject(object: Object3D): Promise<string> {
        return this.addNewObjectAtPose(object, PoseUtils.threeJsPoseIdentityInFrame('world'));
    }

    /**
     * Implementation allowing user to specify the object position
     * @param object The object to add
     * @param position The position of the object
     * @returns UUID of object scene group
     */
    addNewObjectAtPose(object: Object3D, pose: PoseRepresentation): Promise<string> {
        // If the constructor doesn't exist, define the minimal constructor for the object
        if (!this.objectConstructors.has(object.uuid)) {
            this.defineConstructor({
                name: object.uuid,
                /**
                 *
                 * @param constructionData The construction data for the object
                 * @returns
                 */
                parameterizedConstructor: (constructionData: ConstructionData) => {
                    return { object: object, constructionData: constructionData, runtimeData: {} };
                },
            });
        }

        return this.getOrCreateSceneGroup('ur-contributed-objects').then((objEnvironmentGroupUuid) => {
            const sceneObject: SceneObject = {
                objectUuid: object.uuid as UuidType,
                constructionData: {
                    constructorName: object.uuid,
                    version: 1,
                    parameters: {},
                },
                displayName: object.name,
                pose: PoseUtils.asThreeJsPose(pose),
                parentUuid: objEnvironmentGroupUuid,
                layer: 1,
                visible: true,
            };
            return this.upsertSceneObjects([sceneObject]);
        });
    }

    /**
     * Attach an object to a parent.  This can only be used for objecs created by the
     * The object's pose should first be set in the reference frame that matches the parent's reference frame.
     * @param objectUuid The UUID of the object to attach
     * @param parentUuid The UUID of the parent to attach the object to
     * @returns
     */
    attachObjectToParent(objectUuid: string, parentUuid: string): Promise<void> {
        const pCommand: ParentCommand = {
            objectUuid: objectUuid as UuidType,
            type: 'setParent',
            parentUuid: parentUuid as UuidType,
        };
        return this.setObjectProperties([pCommand]);
    }

    /**
     * Attach a tool or other object (i.e., camera) to the tool flange
     * @param toolUuid The UUID of the object to detach
     * @param pose The pose of the object to attach to the tool flange. This should be expressed in the tool flange coordinate frame.
     * @returns
     */
    attachToolToFlange(toolUuid: string, pose: ControllerPose): Promise<void> {
        pose.referenceFrame = 'flange';

        const pCommand: PoseCommand = {
            objectUuid: toolUuid as UuidType,
            type: 'setPose',
            pose: pose,
        };
        return this.setObjectProperties([pCommand]);
    }

    /**
     * Detach a tool or other object (i.e., camera) from the tool flange
     * @param toolUuid The UUID of the object to detach
     * @param stowedPose The pose of the object to detach from the tool flange. This should be expressed in the world coordinate frame.
     * @returns
     */
    detachToolFromFlange(toolUuid: string, stowedPose: ControllerPose): Promise<void> {
        stowedPose.referenceFrame = 'world';

        const pCommand: PoseCommand = {
            objectUuid: toolUuid as UuidType,
            type: 'setPose',
            pose: stowedPose,
        };
        return this.setObjectProperties([pCommand]);
    }

    /**
     * Detach an object from its parent
     * @param objectUuid The UUID of the object to detach
     * @returns
     */
    detachObjectFromParent(objUuid: string): Promise<void> {
        // Set the object's parent to the contributed objects group
        return this.getOrCreateSceneGroup('ur-contributed-objects').then((objEnvironmentGroupUuid) => {
            return this.setObjectProperties([
                {
                    objectUuid: objUuid as UuidType,
                    type: 'setParent',
                    parentUuid: objEnvironmentGroupUuid,
                },
            ]);
        });
    }

    /**
     * Set whether an object is visible or not (note: this will impact any child objects of the object)
     * @param objectUuid The UUID of the object to set the visible property of
     * @param visible Whether the object should be visible or not
     * @returns
     */
    setObjectVisible(objectUuid: UuidType, visible: boolean): Promise<void> {
        const vCommand: VisibleCommand = {
            objectUuid,
            type: 'setVisible',
            visible,
        };
        return this.setObjectProperties([vCommand]);
    }

    /**
     * Set the layer of an object
     * @param objectUuid The UUID of the object to set the layer of
     * @param layer The layer to set
     * @returns
     */
    setObjectLayer(objectUuid: UuidType, layer: number): Promise<void> {
        const lCommand: LayerCommand = {
            objectUuid,
            type: 'setLayer',
            layer,
        };
        return this.setObjectProperties([lCommand]);
    }

    /**
     * Set the pose of an object
     * @param objUuid The UUID of the object to set the pose of
     * @param pose The pose to set
     * @returns
     */
    setObjectPose(objUuid: string, pose: PoseRepresentation): Promise<void> {
        const pCommand: PoseCommand = {
            objectUuid: objUuid as UuidType,
            type: 'setPose',
            pose: pose,
        };
        return this.setObjectProperties([pCommand]);
    }

    /**
     * Set the position of an object
     * @param objUuid The UUID of the object to set the position of
     * @param position The position to set
     * @returns
     */
    setObjectPosition(objUuid: string, position: ZUpPositionMeters): Promise<void> {
        const pCommand: PositionCommand = {
            objectUuid: objUuid as UuidType,
            type: 'setPosition',
            position,
        };
        return this.setObjectProperties([pCommand]);
    }

    /**
     * Set the rotation of an object
     * @param objUuid The UUID of the object to set the rotation of
     * @param rotation The rotation to set
     * @returns
     */
    setObjectRotation(objUuid: string, rotation: ZUpRotationVectorRadians): Promise<void> {
        const pCommand: RotationCommand = {
            objectUuid: objUuid as UuidType,
            type: 'setRotation',
            rotation,
        };
        return this.setObjectProperties([pCommand]);
    }

    /**
     * Set the constructor parameters of an object
     * @param objUuid The UUID of the object to set the constructor parameters of
     * @param parameterLabel The label of the parameter to set
     * @param parameterValue The value of the parameter to set
     * @returns
     */
    setObjectParameters(objUuid: string, parameterLabel: string, parameterValue: any): Promise<void> {
        const parametersCommand: SetConstructorParametersCommand = {
            objectUuid: objUuid as UuidType,
            type: 'setConstructorParameters',
            updateType: 'replaceSpecified',
            parameters: {
                [parameterLabel]: parameterValue,
            },
        };
        return this.setObjectProperties([parametersCommand]);
    }

    /**
     * Set the material properties of an object
     * @param objUuid The UUID of the object to set the material properties of
     * @param materialProperties The material properties to set
     * @returns
     */
    setObjectMaterialProperties(objUuid: string, materialProperties: MaterialPropertyMap): Promise<void> {
        const materialPropertiesCommand: MaterialPropertiesCommand = {
            objectUuid: objUuid as UuidType,
            type: 'setMaterialProperties',
            properties: materialProperties,
        };
        return this.setObjectProperties([materialPropertiesCommand]);
    }

    /**
     * Modify the shared materials of an object
     * @param objUuid The UUID of the object to modify the shared materials of
     * @param properties The properties to modify
     * @returns
     */
    modifySharedMaterials(objUuid: string, properties: MaterialPropertyMap): Promise<void> {
        const modifySharedMaterialsCommand: ModifySharedMaterialsCommand = {
            objectUuid: objUuid as UuidType,
            type: 'modifySharedMaterials',
            detach: false,
            properties: properties,
        };
        return this.setObjectProperties([modifySharedMaterialsCommand]);
    }

    /**
     * Updates or inserts scene objects
     * @param sceneObjects The scene objects to upsert.
     * @returns A promise that resolves when the scene objects have been upserted.
     */
    upsertSceneObjects(sceneObjects: SceneObject[]): Promise<string> {
        return this.request('upsertSceneObjects', {
            sceneObjects,
        });
    }

    /**
     * Deletes a scene object.
     * @param objectUuid The UUID of the object to delete.
     * @returns A promise that resolves when the object has been deleted.
     */
    deleteObject(objectUuid: string): Promise<void> {
        return this.request('deleteObject', { objectUuid });
    }

    /**
     * Allows observing the states of the scene objects.
     * @returns An observable that emits the states of the scene objects.
     */
    observeObjectStates(): Observable<SceneObject[]> {
        return this.postAndObserve('observeObjectStates');
    }

    /**
     * Sets the properties of a scene object.
     * @param properties The properties to set. See PropertyCommand for the set of properties that can be set.
     * @returns A promise that resolves when the properties have been set.
     */
    setObjectProperties(properties: PropertyCommand[]): Promise<void> {
        return this.request('setObjectProperties', { properties });
    }

    /**
     * Requests a UUID to reference a scene group.
     * If the group does not exist, it will be created.
     * @param groupName The name of the scene group to get or create.
     * @returns The UUID of the scene group.
     */
    getOrCreateSceneGroup(groupName: string): Promise<UuidType> {
        return this.request('getOrCreateSceneGroup', { groupName });
    }
}

/**
 * Manipulate scene objects in the 3D view from the Main (UI) Thread
 */
export class PresenterSceneService extends SceneService {
    /**
     * Constructor for the PresenterSceneService.
     * @param communicationChannel The communication channel to use to communicate with the scene service.
     */
    constructor(override readonly communicationChannel: CommunicationChannel) {
        super(communicationChannel);
    }

    /**
     * Get the serializer for a three.js object.
     * @param threeObject The three.js object to get the serializer for.
     * @returns The serializer for the three.js object.
     */
    getObjectSerializer(threeObject: Object3D): { serializerType: string; object: any } {
        return {
            serializerType: 'none',
            object: threeObject,
        };
    }
}

/**
 * Manipulates scene objects in the 3D view from Worker Threads
 */
export class WorkerSceneService extends SceneService {
    /**
     * Constructor for the WorkerSceneService.
     * @param communicationChannel The communication channel to use to communicate with the scene service.
     */
    constructor(override readonly communicationChannel: CommunicationChannel) {
        super(communicationChannel);
    }

    /**
     * Get the serializer for a three.js object.
     * @param threeObject The three.js object to get the serializer for.
     * @returns The serializer for the three.js object.
     */
    getObjectSerializer(threeObject: Object3D): { serializerType: string; object: any } {
        return {
            serializerType: 'threeJsonAndArrayBuffers',
            object: threeObject,
        };
    }
}
