import { Observable } from 'rxjs';
import { URVariable } from '../../types/nodes';
import {
    VARIABLE_VALUE_TYPES,
    VariableDeclaration,
    VariableDescriptionWithReference,
    VariableReference,
} from '../../types/symbols/variable';
import { EventTargetOrCommChannel, MessageInvokerService } from '../message-invoker';

export const VARIABLE_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.variable-service.';

/**
 *
 */
export interface VariablesOptions {
    /**
     * If true, includes deleted variables with isDeleted flag set to true
     */
    includeDeleted?: boolean;
}

/**
 * Service for generating and getting reserved variable names
 */
export class VariableService extends MessageInvokerService {
    /**
     * Create a service for the specific worker
     * @param eventTarget
     */
    constructor(override readonly eventTarget: EventTargetOrCommChannel) {
        super(VARIABLE_SERVICE_MESSAGE_TYPE_BASE, eventTarget);
    }

    /**
     * Get a list of available variables
     * @param options Optional settings for the query
     * @param options.includeDeleted If true, includes deleted variables with isDeleted flag set
     */
    variables(options?: VariablesOptions): Observable<Array<VariableDescriptionWithReference>> {
        return this.postAndObserve('variables', options);
    }

    /**
     * Create a new variable declaration
     * @param name Actual name of the variable. Might be changed by the service to avoid name clashes
     * @param variableType ValueType of the variable
     * @returns Promise resolving to the created variable declaration
     */
    async createVariable(name: string, variableType: (typeof VARIABLE_VALUE_TYPES)[number]): Promise<VariableDeclaration> {
        return this.postAndAwait('createVariable', { name, variableType });
    }

    /**
     * Rename a variable declaration
     * @param variable {VariableDeclaration} Variable declaration to rename
     * @param newName {string} New name of the variable. Might be changed by the service to avoid name clashes
     * @returns {Promise<VariableDeclaration>} The updated variable declaration. Might have new id if the variable name matched a previous variable.
     */
    async renameVariable(variable: VariableDeclaration, newName: string): Promise<VariableDeclaration> {
        return this.postAndAwait('renameVariable', { variable, newName });
    }

    /**
     * Get a variable description from its reference
     * @param reference the variable reference
     * @returns Promise resolving to the variable description or undefined if not found
     */
    async getVariableDescription(reference: VariableReference): Promise<VariableDescriptionWithReference | undefined> {
        return this.postAndAwait('getVariableDescription', { reference });
    }

    /**
     * Upgrade from URVariable to VariableDeclaration | VariableReference.
     * If a variable with the property reference=true is provided, the corresponding VariableReference is returned.
     * If a variable with reference=false is provided, a VariableDeclaration is returned.
     * @param variable URVariable to upgrade
     * @returns Promise resolving to the VariableDeclaration | VariableReference | undefined if not found
     */
    async upgradeURVariable(variable: URVariable): Promise<VariableDeclaration | VariableReference | undefined> {
        return this.postAndAwait('upgradeURVariable', { variable });
    }
}
