import { URValidatorFn, VirtualKeyboardLayout } from '@universal-robots/ui-models';
import { isVariableReference, VARIABLE_VALUE_TYPES, VariableDescriptionWithReference, VariableReference } from '../symbols/variable';

/**
 * Type used for the value in the Value tab
 */
export type ValueType = string | number;

/**
 * Type used for the value in the Expression tab
 */
export type Expression = {
    _IDENTIFIER: 'Expression';
    expression: string;
};

/**
 * Type used to interface with the expression editor.
 * Can be a variable reference, an expression, or a simple value.
 */
export type ExpressionEditorValue = VariableReference | Expression | ValueType;

/**
 * Value types supported in the expression editor
 */
export type ExpressionValueType = (typeof VARIABLE_VALUE_TYPES)[number];

/**
 * These are insertables that can be added to the current expression in
 * the expression tab. They will typically be entries in a dropdown
 * @property label This is what is shown in the dropdown.
 * @property value This is what will be inserted, if different to the label
 * @property details For grouping in the dropdown
 */
export interface ExpressionInsertable {
    label: string;
    value?: string;
    details?: string;
}

/**
 * All the insertables available in the expression editor
 */
export interface ExpressionInsertableModel {
    inputs: ExpressionInsertable[];
    outputs: ExpressionInsertable[];
    builtins: ExpressionInsertable[];
    functions: ExpressionInsertable[];
    variables: VariableDescriptionWithReference[];
}

/**
 * Tabs available in the expression editor
 */
export type ExpressionEditorTab = 'VALUE' | 'VARIABLE' | 'EXPRESSION';

/**
 * Data required to open the expression editor
 */
export interface ExpressionEditorData {
    label: string;
    unit?: string;
    min?: number;
    max?: number;
    step?: number;
    validators?: URValidatorFn[];
    warningValidator?: URValidatorFn;
    expressionEditorValue: ExpressionEditorValue;
    valueType?: ExpressionValueType | ExpressionValueType[];
    tabs?: ExpressionEditorTab[];
    keyboardLayout?: VirtualKeyboardLayout;
}

/**
 * Result returned from the expression editor
 */
export interface ExpressionEditorResult {
    selectedType: ExpressionEditorTab;
    valid: boolean;
    value: ExpressionEditorValue;
}

/**
 * Type guard to check if a value is an Expression
 */
export const isExpression = (value: unknown): value is Expression => {
    return (
        !!value &&
        typeof value === 'object' &&
        Object.hasOwn(value, '_IDENTIFIER') &&
        (value as { _IDENTIFIER: unknown })._IDENTIFIER === 'Expression'
    );
};

/**
 * Type guard to check if a value is a simple ValueType
 */
export const isValueType = (value: unknown): value is ValueType => {
    return typeof value === 'string' || typeof value === 'number';
};

/**
 *
 */
export const inferTab = (value: ExpressionEditorValue): ExpressionEditorTab => {
    if (isVariableReference(value)) {
        return 'VARIABLE';
    } else if (isExpression(value)) {
        return 'EXPRESSION';
    } else {
        return 'VALUE';
    }
};
