import { CommonSymbolDescription } from './common';

export const VARIABLE_DECLARATION_IDENTIFIER = 'VariableDeclaration' as const;
export const VARIABLE_REFERENCE_IDENTIFIER = 'VariableReference' as const;
export const VARIABLE_VALUE_TYPES = [
    'boolean',
    'float',
    'integer',
    'pose',
    'string',
    'matrix',
    'array',
    'waypoint',
    'grid',
    'frame',
    'timer',
    'profile',
] as const;

/**
 * Describes the current state of a variable for use in the UI. Objects of this type should be treated as immutable and should not be saved as its properties are subject to external changes.
 */
export interface VariableDescription extends CommonSymbolDescription {
    valueType: (typeof VARIABLE_VALUE_TYPES)[number];
}
/**
 * Variable declaration
 * Use this type to store variable declarations
 */
export interface VariableDeclaration {
    id: string;
    name: string;
    valueType: (typeof VARIABLE_VALUE_TYPES)[number];
    _IDENTIFIER: typeof VARIABLE_DECLARATION_IDENTIFIER;
}

/**
 * Variable reference.
 * Use this type to store references to variables
 */
export interface VariableReference {
    id: string;
    _IDENTIFIER: typeof VARIABLE_REFERENCE_IDENTIFIER;
}

/**
 * Variable description and a reference
 * Holds a combined object @type VariableDescription with extended @type VariableReference property "reference"
 */
export type VariableDescriptionWithReference = VariableDescription & { reference: VariableReference };

/**
 * VariableReference guard function
 */
export const isVariableReference = (entity: unknown): entity is VariableReference => {
    return (
        !!entity &&
        typeof entity === 'object' &&
        Object.hasOwn(entity, 'id') &&
        Object.hasOwn(entity, '_IDENTIFIER') &&
        (entity as { _IDENTIFIER: unknown })._IDENTIFIER === VARIABLE_REFERENCE_IDENTIFIER
    );
};

/**
 * VariableDeclaration guard function
 */
export const isVariableDeclaration = (entity: unknown): entity is VariableDeclaration => {
    return (
        !!entity &&
        typeof entity === 'object' &&
        Object.hasOwn(entity, 'id') &&
        Object.hasOwn(entity, 'name') &&
        Object.hasOwn(entity, 'valueType') &&
        Object.hasOwn(entity, '_IDENTIFIER') &&
        (entity as { _IDENTIFIER: unknown })._IDENTIFIER === VARIABLE_DECLARATION_IDENTIFIER
    );
};
