import { Color, Object3D, Texture } from 'three';
import { OptionalPromise } from '../../types/behavior';
import { PoseRepresentation, PositionRepresentation, RotationRepresentation } from '../../types/nodes';

/**
 * Type for a unique identifier for a scene object.
 */
export type UuidType = `${string}-${string}-${string}-${string}-${string}`;

/**
 * The interface used to specify the data needed to construct a scene object.
 */
export interface ConstructionData {
    /**
     * The version of the construction data.
     */
    version: number;
    /**
     * The name/identifier of the constructor to use to construct the scene object.
     */
    constructorName?: string;
    /**
     * The parameters to pass to the constructor. These are used to configure the scene object
     */
    parameters?: Record<string, any>;
}

/**
 * SceneObject defines the data needed to represent a 3D object in the scene.
 */
export interface SceneObject {
    /**
     * The unique identifier for the scene object.
     */
    objectUuid: UuidType;
    /**
     * The data needed to construct the scene object.
     */
    constructionData: ConstructionData;
    /**
     * The display name of the scene object.
     */
    displayName: string;
    /**
     * The pose of the scene object.
     * This can be defined in either the standard Three.js PoseRepresentation,
     * or the UR ControllerPose representation.
     */
    pose: PoseRepresentation;
    /**
     * The unique identifier of the parent of the scene object.
     */
    parentUuid: UuidType;
    /**
     * The layer of the scene object.
     * Objects on higher layers are rendered on top of objects on lower layers.
     */
    layer: number;
    /**
     * Whether the scene object is visible.
     * If not specified, the scene object is visible by default.
     */
    visible?: boolean;
}

/**
 * RuntimeData is used to store arbitrary data about a scene object.
 */
export interface RuntimeData {
    /**
     * The unique identifier of the scene object.
     */
    objectUuid: UuidType;
    /**
     * The runtime data to store/use for the scene object.
     */
    runtimeData: Record<string, any>;
}

/**
 * PoseCommand is used to set the pose of a scene object.
 */
export interface PoseCommand {
    /**
     * The unique identifier of the scene object.
     */
    objectUuid: UuidType;
    /**
     * The type of command to execute.
     */
    type: 'setPose';
    /**
     * The pose to set.
     */
    pose: PoseRepresentation;
}

/**
 * PositionCommand is used to set the position ( but not rotation) of a scene object.
 */
export interface PositionCommand {
    /**
     * The unique identifier of the scene object.
     */
    objectUuid: UuidType;
    /**
     * The type of command to execute.
     */
    type: 'setPosition';
    /**
     * The name of the sub-object to set the position of. This is used if only a
     * subset of the scene object's children need to be moved.
     */
    subObjectName?: string;
    /**
     * The position to set, including the reference frame
     */
    position: PositionRepresentation;
}

/**
 * RotationCommand is used to set the rotation ( but not position) of a scene object.
 */
export interface RotationCommand {
    /**
     * The unique identifier of the scene object.
     */
    objectUuid: UuidType;
    /**
     * The type of command to execute.
     */
    type: 'setRotation';
    /**
     * The name of the sub-object to set the rotation of. This is used if only a
     * subset of the scene object's children need to be rotated.
     */
    subObjectName?: string;
    /**
     * The rotation to set, including the reference frame
     */
    rotation: RotationRepresentation;
}

/**
 * VisibleCommand is used to set the visibility of a scene object.
 */
export interface VisibleCommand {
    /**
     * The unique identifier of the scene object.
     */
    objectUuid: UuidType;
    /**
     * The type of command to execute.
     */
    type: 'setVisible';
    /**
     * The visibility to set.
     */
    visible: boolean;
    /**
     * The name of the sub-object to set the visibility of. This is used if only a
     * subset of the scene object's children need to be made visible/invisible.
     */
    subObjectName?: string;
}

/**
 * LayerCommand is used with to move objects between layers
 */
export interface LayerCommand {
    /**
     * The unique identifier of the scene object.
     */
    objectUuid: UuidType;
    /**
     * The type of command to execute.
     */
    type: 'setLayer';
    /**
     * The name of the sub-object to set the layer of. This is used if only a
     * subset of the scene object's children need to be moved to a different layer.
     */
    subObjectName?: string;
    /**
     * The layer to move the object to.
     */
    layer: number;
}

/**
 * ParentCommand is used to change the parent of a scene object.
 */
export interface ParentCommand {
    /**
     * The unique identifier of the scene object.
     */
    objectUuid: UuidType;
    /**
     * The type of command to execute.
     */
    type: 'setParent';
    /**
     * The unique identifier of the new parent.
     */
    parentUuid: UuidType;
}

/**
 *  ConstructorParameterUpdateType is used to specify how to update the
 *  constructor parameters of a scene object.
 *  - replaceAll: Replace all the constructor parameters with the new values (or default values if not specified).
 *  - replaceSpecified: Replace only the specified constructor parameters with the new values.
 */
export type ConstructorParameterUpdateType = 'replaceAll' | 'replaceSpecified';

/**
 * SetConstructorParametersCommand is used to set the constructor parameters of a scene object.
 */
export interface SetConstructorParametersCommand {
    /**
     * The unique identifier of the scene object.
     */
    objectUuid: UuidType;
    /**
     * The type of command to execute.
     */
    type: 'setConstructorParameters';
    /**
     * The type of update to perform.
     */
    updateType: ConstructorParameterUpdateType;
    /**
     * The constructor parameters to set.
     */
    parameters: Record<string, any>;
}

/**
 * MaterialPropertyMap stores the rendering properties of materials in a scene
 */
export type MaterialPropertyMap = Record<string, Texture | string | number | Color | boolean | null>;

/**
 * MaterialPropertiesCommand is used to set the rendering properties of a scene object
 */
export interface MaterialPropertiesCommand {
    /**
     * The unique identifier of the scene object.
     */
    objectUuid: UuidType;
    /**
     * The type of command to execute.
     */
    type: 'setMaterialProperties';
    /**
     * The name of the sub-object to set the material properties of. This is used if only a
     * subset of the scene object's children need to have their material properties set.
     */
    subObjectName?: string;
    /**
     * The index of the material to set the properties of.
     */
    materialIndex?: number;
    /**
     * The properties to set.
     */
    properties: MaterialPropertyMap;
}

/**
 * ModifySharedMaterialsCommand is used to modify the shared materials of a scene object.
 */
export interface ModifySharedMaterialsCommand {
    /**
     * The unique identifier of the scene object.
     */
    objectUuid: UuidType;
    /**
     * The type of command to execute.
     */
    type: 'modifySharedMaterials';
    /**
     * Whether to detach the materials from the scene object.
     */
    detach: boolean;
    /**
     * The name of the sub-object to modify the shared materials of. This is used if only a
     * subset of the scene object's children need to have their shared materials modified.
     */
    subObjectName?: string;
    /**
     * The properties to modify.
     */
    properties: MaterialPropertyMap;
}

/**
 * PropertyCommand defines the set of commands that can be used to create and modify
 * scene objects in the scene.
 */
export type PropertyCommand =
    | PoseCommand
    | PositionCommand
    | RotationCommand
    | VisibleCommand
    | ParentCommand
    | LayerCommand
    | SetConstructorParametersCommand
    | MaterialPropertiesCommand
    | ModifySharedMaterialsCommand;

/**
 * ConstructorType is used to specify the type of constructor to use to construct a scene object.
 * - PARAMETERIZED: A parameterized constructor is a constructor that takes a set of parameters and returns a scene object.
 */
export enum ConstructorType {
    PARAMETERIZED = 'parameterized',
}

/**
 * ConstructorDefinitionMessageAPI is used to define a constructor for a scene object.
 */
export interface ConstructorDefinitionMessageAPI {
    /**
     * The name of the constructor.
     */
    constructorName: string;
    /**
     * The type of constructor.
     */
    constructorType: ConstructorType;
}

/**
 * The signature of a constructor function.  It takes as an argument construction data,
 * and returns a promise of an object and any additional construction or runtime data.
 */
export type ConstructorSignature = (
    constructionData: ConstructionData,
) => OptionalPromise<{ object: Object3D; constructionData: ConstructionData; runtimeData: Record<string, any> }>;

/**
 * The API interface to define an constructor for a type of scene object.
 */
export interface ConstructorDefinitionAPI {
    /**
     * The name of the constructor.
     */
    name: string;
    /**
     * The parameterized constructor function.
     */
    parameterizedConstructor?: ConstructorSignature;
}
