import { WorkerModule } from 'threads';
import { expose } from 'threads/worker';
import { setValidationContext } from './services/validation-context-holder';
import { ProgramType } from './types/context';
import { registerSerializers } from './types/worker-serializers';

/**
 * Queue to sequentialize behavior executions within each worker.
 * This prevents race conditions when multiple validations or code generations
 * run concurrently, ensuring the validation context is correctly maintained for each call.
 */
let behaviorQueue = Promise.resolve();

/**
 * Extract programType from the second argument (ValidationContext / ScriptContext) and
 *    set it as the thread-local validation context for the duration of the call
 * @param context
 */
function extractProgramType(context: unknown): ProgramType | undefined {
    if (context && typeof context === 'object' && 'programType' in context) {
        return context.programType as ProgramType;
    }
    return undefined;
}

/**
 * Wraps a behavior method (validator or code generator) to:
 * 1. Sequentialize execution via the shared queue, preventing context corruption
 *
 */
function wrapWithContextQueue(originalFn: (...args: unknown[]) => unknown) {
    return (node: unknown, context: unknown, ...rest: unknown[]): Promise<unknown> => {
        const taskPromise = behaviorQueue
            .catch(() => undefined)
            .then(async () => {
                const programType = extractProgramType(context);
                setValidationContext(programType !== undefined ? { programType } : null);
                try {
                    return await originalFn(node, context, ...rest); // NOSONAR - await required inside try/finally to ensure context cleanup runs after async completion
                } finally {
                    setValidationContext(null);
                }
            });
        behaviorQueue = taskPromise.then(() => undefined);
        return taskPromise;
    };
}

/**
 * Wraps behavior methods that use ValidationContext to ensure proper context handling
 */
function wrapBehaviors(behaviors: WorkerModule<any>): WorkerModule<any> {
    for (const method of ['validator', 'generateCodeBeforeChildren', 'generateCodeAfterChildren', 'generateCodePreamble'] as const) {
        if (behaviors[method]) {
            behaviors[method] = wrapWithContextQueue(behaviors[method]);
        }
    }
    return behaviors;
}

/**
 * Common handler for behaviors
 */
const behaviorHandler = (behaviors: WorkerModule<any>) => {
    registerSerializers();
    expose(wrapBehaviors(behaviors));
};

/**
 * Registers a Program behavior object allowing the programming area to
 * call the behavior methods.
 *
 * @param behaviors The ProgramBehaviors object to register
 */
export const registerProgramBehavior = behaviorHandler;

/**
 * Registers an Application behavior object allowing the application area to
 * call the behavior methods.
 *
 * @param behaviors The ApplicationBehaviors object to register
 */
export const registerApplicationBehavior = behaviorHandler;

/**
 * Registers a Source behavior object allowing various entities to call source
 * behavior methods
 *
 * @param behaviors The SourceBehaviors object to register
 */
export const registerSourceBehavior = behaviorHandler;

/**
 * Registers a Smart skill behavior object allowing each smart skill to call its execution methods
 * behavior methods
 *
 * @param behaviors The SmartSkillsBehaviors object to register
 */
export const registerSmartSkillBehavior = behaviorHandler;

/**
 * Registers a Operator Screen behavior object allowing each operator screen to call its
 * behavior methods
 *
 * @param behaviors The OperatorScreenBehaviors object to register
 */
export const registerOperatorScreenBehavior = behaviorHandler;

/**
 * Registers a System Info behavior object allowing each system info screen to call its
 * behavior methods
 *
 * @param behaviors The SystemInfoBehaviors object to register
 */
export const registerSystemInfoBehavior = behaviorHandler;

/**
 * Registers a Sidebar behavior object allowing each sidebar to call its
 * behavior methods
 *
 * @param behaviors The SidebarBehaviors object to register
 */
export const registerSidebarBehavior = behaviorHandler;
