import { Observable } from 'rxjs';
import { URFunction } from '../../types/nodes';
import { FunctionDeclaration, FunctionDescriptionWithReference, FunctionReference } from '../../types/symbols';
import { EventTargetOrCommChannel, MessageInvokerService } from '../message-invoker';

export const FUNCTION_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.function-service.';
/**
 * Options for the functions endpoint
 */
export interface FunctionsOptions {
    /**
     * If true, includes deleted functions with isDeleted flag set to true
     */
    includeDeleted?: boolean;
}

/**
 * Service for interacting with functions
 */
export class FunctionService extends MessageInvokerService {
    /**
     * Create a service for the specific worker
     * @param eventTarget
     */
    constructor(override readonly eventTarget: EventTargetOrCommChannel) {
        super(FUNCTION_SERVICE_MESSAGE_TYPE_BASE, eventTarget);
    }

    /**
     * Get a list of available functions
     * @param options Optional settings for the query
     * @param options.includeDeleted If true, includes deleted functions with isDeleted flag set
     */
    functions(options?: FunctionsOptions): Observable<Array<FunctionDescriptionWithReference>> {
        return this.postAndObserve('functions', options);
    }

    /**
     * Create a new function declaration
     * @param name Actual name of the function. Might be changed by the service to avoid name clashes
     * @returns Promise resolving to the created function declaration
     */
    async createFunction(name: string, moduleName?: string): Promise<FunctionDeclaration> {
        return this.postAndAwait('createFunction', { name, moduleName });
    }

    /**
     * Get a function description from its reference
     * @param reference the function reference
     * @returns Promise resolving to the function description or undefined if not found
     */
    async getFunctionDescription(reference: FunctionReference): Promise<FunctionDescriptionWithReference | undefined> {
        return this.postAndAwait('getFunctionDescription', { reference });
    }
    /**
     * Upgrade an existing function to the latest version
     * @param func The function to upgrade
     * @returns Promise resolving to the upgraded function description or undefined if not found
     */
    async upgradeURFunction<T extends FunctionDeclaration | FunctionReference>(func: URFunction): Promise<T | undefined> {
        return this.postAndAwait('upgradeURFunction', { func });
    }
}
