import { ALL_UNIT_LABELS, AllUnitLabels } from '@universal-robots/utilities-units';

export type AllUnits = AllUnitLabels;

export const AllUnitStrings: Set<AllUnits> = new Set<AllUnits>(ALL_UNIT_LABELS);
export interface Value<U extends AllUnits = AllUnits> {
    value: number;
    unit: U;
}

export interface ValueRange<U extends AllUnits = AllUnits> {
    min: number;
    max: number;
    unit: U;
}
